// icIC3 -- friends/FoF (not living in either country) with messages
// located in China AND Germany within a 1500-day window from
// 2010-01-01; [personId, xCount, yCount], (x+y desc, id asc), top 20.
func icIC3(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		cx, ok1 := nodeByName(g, "Country", "China")
		cy, ok2 := nodeByName(g, "Country", "Germany")
		if !ok1 || !ok2 {
			return [][]any{}, nil
		}
		startDay := dayFromCivil(2010, 1, 1)
		endDay := startDay + 1500
		reach := g.Neighborhood(person, chickpeas.Both, g.Match("KNOWS"), 1, 2)
		var rows [][]any
		for p := range reach.Iter() {
			if home, ok := g.Follow(p,
				chickpeas.Step{Dir: chickpeas.Outgoing, RelType: "IS_LOCATED_IN"},
				chickpeas.Step{Dir: chickpeas.Outgoing, RelType: "IS_PART_OF"},
			); ok && (home == cx || home == cy) {
				continue
			}
			var xc, yc int64
			for msg := range g.Neighbors(p, chickpeas.Incoming, "HAS_CREATOR") {
				day := i64At(dayCol, msg)
				if day < startDay || day >= endDay {
					continue
				}
				if c, ok := g.FirstNeighbor(msg, chickpeas.Outgoing, "IS_LOCATED_IN"); ok {
					switch c {
					case cx:
						xc++
					case cy:
						yc++
					}
				}
			}
			if xc > 0 && yc > 0 {
				rows = append(rows, []any{i64At(idCol, p), xc, yc})
			}
		}
		return sortTruncate(rows, 20, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64)+a[2].(int64), b[1].(int64)+b[2].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// icIC4 -- new topics: tags on friends' Posts inside the window that
// never appeared on their Posts before it; [tagName, postCount],
// (count desc, name asc), top 10.
func icIC4(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		endDay := int64(icIC4Start + icIC4Dur)
		posts, _ := g.NodesWithLabel("Post")
		inWindow := map[chickpeas.NodeID]int64{}
		before := map[chickpeas.NodeID]bool{}
		for friend := range g.Neighbors(person, chickpeas.Both, "KNOWS") {
			for post := range g.Neighbors(friend, chickpeas.Incoming, "HAS_CREATOR") {
				if posts == nil || !posts.Contains(post) {
					continue
				}
				day := i64At(dayCol, post)
				if day < icIC4Start {
					for t := range g.Neighbors(post, chickpeas.Outgoing, "HAS_TAG") {
						before[t] = true
					}
				} else if day < endDay {
					for t := range g.Neighbors(post, chickpeas.Outgoing, "HAS_TAG") {
						inWindow[t]++
					}
				}
			}
		}
		var rows [][]any
		for t, c := range inWindow {
			if !before[t] {
				rows = append(rows, []any{strAt(g, t, "name"), c})
			}
		}
		return sortTruncate(rows, 10, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64), b[1].(int64)),
				cmpStrAsc(a[0].(string), b[0].(string)),
			)
		}), nil
	}, nil
}

// icIC5 -- new groups: forums the friends/FoF joined after 2011-01-01,
// ranked by those members' Posts in each forum; [forumId, postCount],
// (count desc, id asc), top 20.
func icIC5(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	jdCol, ok := g.RelCol("joinDate")
	if !ok {
		return nil, fmt.Errorf("rel column joinDate missing")
	}
	jd := jdCol.I64()
	return func() ([][]any, error) {
		minDay := dayFromCivil(2011, 1, 1)
		reach := g.Neighborhood(person, chickpeas.Both, g.Match("KNOWS"), 1, 2)
		forumCounts := map[chickpeas.NodeID]int64{}
		qforums := map[chickpeas.NodeID]bool{}
		for p := range reach.Iter() {
			clear(qforums)
			for e := range g.Rels(p, chickpeas.Incoming, "HAS_MEMBER") {
				if ms, ok := jd.Get(e.Pos); ok && floorDiv(ms, msPerDay) > minDay {
					qforums[e.Neighbor] = true
				}
			}
			if len(qforums) == 0 {
				continue
			}
			for post := range g.Neighbors(p, chickpeas.Incoming, "HAS_CREATOR") {
				if forum, ok := g.FirstNeighbor(post, chickpeas.Incoming, "CONTAINER_OF"); ok && qforums[forum] {
					forumCounts[forum]++
				}
			}
		}
		rows := make([][]any, 0, len(forumCounts))
		for f, c := range forumCounts {
			rows = append(rows, []any{i64At(idCol, f), c})
		}
		return sortTruncate(rows, 20, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64), b[1].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// icIC6 -- tag co-occurrence on friends/FoF Posts carrying the seed
// tag; [tagName, postCount], (count desc, name asc), top 10.
func icIC6(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		target, ok := nodeByName(g, "Tag", icSeedTag)
		if !ok {
			return [][]any{}, nil
		}
		posts, _ := g.NodesWithLabel("Post")
		reach := g.Neighborhood(person, chickpeas.Both, g.Match("KNOWS"), 1, 2)
		counts := map[chickpeas.NodeID]int64{}
		var tags []chickpeas.NodeID
		for p := range reach.Iter() {
			for post := range g.Neighbors(p, chickpeas.Incoming, "HAS_CREATOR") {
				if posts == nil || !posts.Contains(post) {
					continue
				}
				tags = tags[:0]
				hasTarget := false
				for t := range g.Neighbors(post, chickpeas.Outgoing, "HAS_TAG") {
					if t == target {
						hasTarget = true
					}
					tags = append(tags, t)
				}
				if !hasTarget {
					continue
				}
				for _, t := range tags {
					if t != target {
						counts[t]++
					}
				}
			}
		}
		rows := make([][]any, 0, len(counts))
		for t, c := range counts {
			rows = append(rows, []any{strAt(g, t, "name"), c})
		}
		return sortTruncate(rows, 10, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64), b[1].(int64)),
				cmpStrAsc(a[0].(string), b[0].(string)),
			)
		}), nil
	}, nil
}

// icIC7 -- the 20 most recent likers of the seed's messages (latest
// like per liker); [likeMs, likerId, isNew], (ms desc, id asc); isNew
// = not a direct friend (0/1).
func icIC7(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	ldCol, ok := g.RelCol("creationDate")
	if !ok {
		return nil, fmt.Errorf("rel column creationDate missing")
	}
	ld := ldCol.I64()
	return func() ([][]any, error) {
		friends := map[chickpeas.NodeID]bool{}
		for f := range g.Neighbors(person, chickpeas.Both, "KNOWS") {
			friends[f] = true
		}
		type likeRec struct {
			ms  int64
			msg chickpeas.NodeID
		}
		best := map[chickpeas.NodeID]likeRec{}
		for msg := range g.Neighbors(person, chickpeas.Incoming, "HAS_CREATOR") {
			for e := range g.Rels(msg, chickpeas.Incoming, "LIKES") {
				lms, _ := ld.Get(e.Pos)
				cur, seen := best[e.Neighbor]
				if !seen || lms > cur.ms || (lms == cur.ms && msg < cur.msg) {
					best[e.Neighbor] = likeRec{lms, msg}
				}
			}
		}
		rows := make([][]any, 0, len(best))
		for liker, rec := range best {
			isNew := int64(1)
			if friends[liker] {
				isNew = 0
			}
			rows = append(rows, []any{rec.ms, i64At(idCol, liker), isNew})
		}
		return sortTruncate(rows, 20, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[0].(int64), b[0].(int64)),
				cmpI64Asc(a[1].(int64), b[1].(int64)),
			)
		}), nil
	}, nil
}

// icIC8 -- the 20 most recent replies to the seed's messages;
// [replyMs] (ms desc, reply id asc).
func icIC8(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	msCol, err := nodeI64Col(g, "ms")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		top := msTop{k: 20}
		for msg := range g.Neighbors(person, chickpeas.Incoming, "HAS_CREATOR") {
			for reply := range g.Neighbors(msg, chickpeas.Incoming, "REPLY_OF") {
				top.push(i64At(msCol, reply), reply)
			}
		}
		return top.msRows(), nil
	}, nil
}

// icIC9 -- the 20 most recent messages by friends and FoF on/before
// maxDay; [creationMs] (ms desc, message id asc).
func icIC9(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	msCol, err := nodeI64Col(g, "ms")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		reach := g.Neighborhood(person, chickpeas.Both, g.Match("KNOWS"), 1, 2)
		top := msTop{k: 20}
		for p := range reach.Iter() {
			for msg := range g.Neighbors(p, chickpeas.Incoming, "HAS_CREATOR") {
				if i64At(dayCol, msg) > icSeedMaxDay {
					continue
				}
				top.push(i64At(msCol, msg), msg)
			}
		}
		return top.msRows(), nil
	}, nil
}

// icIC10 -- friend recommendation (month 1): FoF at exactly 2 hops born
// in [Jan 21, Feb 22), scored by tagged-vs-untagged Posts against the
// seed's interests; [personId, score], (score desc, id asc), top 10.
func icIC10(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	bmonCol, err := nodeI64Col(g, "bmon")
	if err != nil {
		return nil, err
	}
	bdomCol, err := nodeI64Col(g, "bdom")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		const month = 1
		next := int64(month%12 + 1)
		interests := map[chickpeas.NodeID]bool{}
		for t := range g.Neighbors(person, chickpeas.Outgoing, "HAS_INTEREST") {
			interests[t] = true
		}
		posts, _ := g.NodesWithLabel("Post")
		reach := g.Neighborhood(person, chickpeas.Both, g.Match("KNOWS"), 2, 2)
		var rows [][]any
		for foaf := range reach.Iter() {
			bmon, bdom := i64At(bmonCol, foaf), i64At(bdomCol, foaf)
			if !((bmon == month && bdom >= 21) || (bmon == next && bdom < 22)) {
				continue
			}
			var common, uncommon int64
			for msg := range g.Neighbors(foaf, chickpeas.Incoming, "HAS_CREATOR") {
				if posts == nil || !posts.Contains(msg) {
					continue
				}
				tagged := false
				for t := range g.Neighbors(msg, chickpeas.Outgoing, "HAS_TAG") {
					if interests[t] {
						tagged = true
						break
					}
				}
				if tagged {
					common++
				} else {
					uncommon++
				}
			}
			rows = append(rows, []any{i64At(idCol, foaf), common - uncommon})
		}
		return sortTruncate(rows, 10, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64), b[1].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// icIC11 -- job referral (Indonesia, workFrom < 2030): the <=2-hop
// neighbourhood's work records at companies of the country; [personId,
// companyName, workFrom], (workFrom asc, id asc, name desc), top 10.
func icIC11(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	wfCol, ok := g.RelCol("workFrom")
	if !ok {
		return nil, fmt.Errorf("rel column workFrom missing")
	}
	wf := wfCol.I64()
	return func() ([][]any, error) {
		const year = 2030
		country, ok := nodeByName(g, "Country", icSeedCountry)
		if !ok {
			return [][]any{}, nil
		}
		places := map[chickpeas.NodeID]bool{country: true}
		for city := range g.Neighbors(country, chickpeas.Incoming, "IS_PART_OF") {
			places[city] = true
		}
		inCountry := map[chickpeas.NodeID]bool{}
		if comps, ok := g.NodesWithLabel("Company"); ok {
			for org := range comps.Iter() {
				for pl := range g.Neighbors(org, chickpeas.Outgoing, "IS_LOCATED_IN") {
					if places[pl] {
						inCountry[org] = true
						break
					}
				}
			}
		}
		reach := g.Neighborhood(person, chickpeas.Both, g.Match("KNOWS"), 1, 2)
		var rows [][]any
		for p := range reach.Iter() {
			for e := range g.Rels(p, chickpeas.Outgoing, "WORK_AT") {
				if !inCountry[e.Neighbor] {
					continue
				}
				from, ok := wf.Get(e.Pos)
				if !ok || from >= year {
					continue
				}
				rows = append(rows, []any{i64At(idCol, p), strAt(g, e.Neighbor, "name"), from})
			}
		}
		return sortTruncate(rows, 10, func(a, b []any) bool {
			return cmpChain(
				cmpI64Asc(a[2].(int64), b[2].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
				-cmpStrAsc(a[1].(string), b[1].(string)),
			)
		}), nil
	}, nil
}

// icIC12 -- expert search (TagClass Saint + descendants): direct
// friends by replies to Posts tagged under the class; [personId,
// replyCount], (count desc, id asc), top 20.
func icIC12(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		rootClass, ok := nodeByName(g, "TagClass", icSeedClass)
		if !ok {
			return [][]any{}, nil
		}
		classSet := g.BFSDistances(rootClass, chickpeas.Incoming, g.Match("IS_SUBCLASS_OF"), chickpeas.NoMaxDepth)
		qualTag := func(t chickpeas.NodeID) bool {
			for c := range g.Neighbors(t, chickpeas.Outgoing, "HAS_TYPE") {
				if _, in := classSet[c]; in {
					return true
				}
			}
			return false
		}
		posts, _ := g.NodesWithLabel("Post")
		var rows [][]any
		for friend := range g.Neighbors(person, chickpeas.Both, "KNOWS") {
			var count int64
			for c := range g.Neighbors(friend, chickpeas.Incoming, "HAS_CREATOR") {
				for parent := range g.Neighbors(c, chickpeas.Outgoing, "REPLY_OF") {
					if posts == nil || !posts.Contains(parent) {
						continue
					}
					matched := false
					for t := range g.Neighbors(parent, chickpeas.Outgoing, "HAS_TAG") {
						if qualTag(t) {
							matched = true
						}
					}
					if matched {
						count++
					}
				}
			}
			if count > 0 {
				rows = append(rows, []any{i64At(idCol, friend), count})
			}
		}
		return sortTruncate(rows, 20, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64), b[1].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// icIC13 -- unweighted shortest knows-path length between the seeds;
// [[hops]] (-1 when unreachable).
func icIC13(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	personB, err := icPersonB(g)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		unit := func(chickpeas.NodeID, chickpeas.RelRef) float64 { return 1.0 }
		if cost, ok := g.WeightedShortestPath(person, personB, chickpeas.Both, g.Match("KNOWS"), unit); ok {
			return [][]any{{int64(cost)}}, nil
		}
		return [][]any{{int64(-1)}}, nil
	}, nil
}

// icIC14 -- weighted shortest knows-path cost between the seeds, edge
// cost 1/(reply interactions + 1); [[cost]] or [] when unreachable.
// The interaction map is built in the untimed prepare phase (the Rust
// harness times only the search).
func icIC14(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := icPerson(g)
	if err != nil {
		return nil, err
	}
	personB, err := icPersonB(g)
	if err != nil {
		return nil, err
	}
	interaction := buildInteractionMap(g)
	return func() ([][]any, error) {
		weight := func(from chickpeas.NodeID, rel chickpeas.RelRef) float64 {
			return 1.0 / (float64(interaction[pairKey(from, rel.Neighbor)]) + 1.0)
		}
		if cost, ok := g.WeightedShortestPath(person, personB, chickpeas.Both, g.Match("KNOWS"), weight); ok && finite(cost) {
			return [][]any{{cost}}, nil
		}
		return [][]any{}, nil
	}, nil
}

