// icIS6 -- the forum and moderator of the seed post; [[forumId,
// moderatorId]].
func icIS6(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	post, err := icSeedPost(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	var roots chickpeas.RootsVia
	if rt, ok := g.RelType("REPLY_OF"); ok {
		roots = g.RootsVia(rt, chickpeas.Outgoing)
	}
	return func() ([][]any, error) {
		root := post
		if roots != nil {
			root = roots[post]
		}
		forum, ok := g.FirstNeighbor(root, chickpeas.Incoming, "CONTAINER_OF")
		if !ok {
			return [][]any{}, nil
		}
		moderator, ok := g.FirstNeighbor(forum, chickpeas.Outgoing, "HAS_MODERATOR")
		if !ok {
			return [][]any{}, nil
		}
		return [][]any{{i64At(idCol, forum), i64At(idCol, moderator)}}, nil
	}, nil
}

// icIS7 -- direct replies to the seed post; [replyMs, authorId, knows]
// (ms desc, author id asc); knows = author is a friend of the post's
// author (0/1).
func icIS7(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	post, err := icSeedPost(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	msCol, err := nodeI64Col(g, "ms")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		author, hasAuthor := creatorOf(g, post)
		authorFriends := map[chickpeas.NodeID]bool{}
		if hasAuthor {
			for f := range g.Neighbors(author, chickpeas.Both, "KNOWS") {
				authorFriends[f] = true
			}
		}
		var rows [][]any
		for reply := range g.Neighbors(post, chickpeas.Incoming, "REPLY_OF") {
			ra, ok := creatorOf(g, reply)
			knows := int64(0)
			raID := int64(0)
			if ok {
				raID = i64At(idCol, ra)
				if hasAuthor && ra != author && authorFriends[ra] {
					knows = 1
				}
			}
			rows = append(rows, []any{i64At(msCol, reply), raID, knows})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[0].(int64), b[0].(int64)),
				cmpI64Asc(a[1].(int64), b[1].(int64)),
			)
		}), nil
	}, nil
}

// GABFS is breadth-first depth from source over forward rels;
// unreachable nodes get MaxInt64, per the spec.
func GABFS(g *chickpeas.Snapshot, source uint32, directed bool) []int64 {
	n := g.NodeCount()
	dir := gaFwd(directed)
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	if source >= n {
		return dist
	}
	dist[source] = 0
	queue := make([]uint32, 0, n)
	queue = append(queue, source)
	for head := 0; head < len(queue); head++ {
		u := queue[head]
		du := dist[u]
		for w := range g.Neighbors(u, dir) {
			if dist[w] == math.MaxInt64 {
				dist[w] = du + 1
				queue = append(queue, w)
			}
		}
	}
	return dist
}

// GAPageRank runs `iterations` synchronous updates with the given
// damping; sinks redistribute their rank uniformly. Pull formulation:
// each node sums its in-neighbours' shares into a disjoint slot.
func GAPageRank(g *chickpeas.Snapshot, directed bool, damping float64, iterations int) []float64 {
	n := int(g.NodeCount())
	if n == 0 {
		return nil
	}
	nf := float64(n)
	out := gaFwd(directed)
	inDir := chickpeas.Incoming
	if !directed {
		inDir = chickpeas.Both
	}
	outdeg := make([]uint32, n)
	parallel.For(n, func(lo, hi int) {
		for v := lo; v < hi; v++ {
			var d uint32
			for range g.Neighbors(uint32(v), out) {
				d++
			}
			outdeg[v] = d
		}
	})
	pr := make([]float64, n)
	for i := range pr {
		pr[i] = 1.0 / nf
	}
	next := make([]float64, n)
	for range iterations {
		var dangling float64
		for v := range n {
			if outdeg[v] == 0 {
				dangling += pr[v]
			}
		}
		base := (1.0-damping)/nf + damping*dangling/nf
		parallel.For(n, func(lo, hi int) {
			for v := lo; v < hi; v++ {
				var pull float64
				for u := range g.Neighbors(uint32(v), inDir) {
					if d := outdeg[u]; d > 0 {
						pull += pr[u] / float64(d)
					}
				}
				next[v] = base + damping*pull
			}
		})
		pr, next = next, pr
	}
	return pr
}

// GAWCC labels each node with the smallest node id in its weakly
// connected component (undirected flood in ascending sweep order).
func GAWCC(g *chickpeas.Snapshot) []uint32 {
	n := g.NodeCount()
	comp := make([]uint32, n)
	for i := range comp {
		comp[i] = math.MaxUint32
	}
	var stack []uint32
	for s := range n {
		if comp[s] != math.MaxUint32 {
			continue
		}
		comp[s] = s
		stack = append(stack[:0], s)
		for len(stack) > 0 {
			v := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			for u := range g.Neighbors(v, chickpeas.Both) {
				if comp[u] == math.MaxUint32 {
					comp[u] = s
					stack = append(stack, u)
				}
			}
		}
	}
	return comp
}

// GACDLPSeeded is synchronous label propagation from explicit initial
// labels (seed with original vertex ids so the smallest-label tie-break
// operates in vertex-id space, matching the references). Directed
// graphs tally incoming and outgoing separately, so a mutual rel counts
// twice.
func GACDLPSeeded(g *chickpeas.Snapshot, directed bool, iterations int, init []uint32) []uint32 {
	n := int(g.NodeCount())
	cur := slices.Clone(init)
	next := make([]uint32, n)
	for range iterations {
		parallel.For(n, func(lo, hi int) {
			// Per-chunk scratch (a few dozen chunks per pass); reused
			// across the chunk's nodes.
			var buf []uint32
			for v := lo; v < hi; v++ {
				buf = buf[:0]
				if directed {
					for u := range g.Neighbors(uint32(v), chickpeas.Outgoing) {
						buf = append(buf, cur[u])
					}
					for u := range g.Neighbors(uint32(v), chickpeas.Incoming) {
						buf = append(buf, cur[u])
					}
				} else {
					for u := range g.Neighbors(uint32(v), chickpeas.Both) {
						buf = append(buf, cur[u])
					}
				}
				slices.Sort(buf)
				best, bestCount := cur[v], 0
				for i := 0; i < len(buf); {
					lab := buf[i]
					j := i + 1
					for j < len(buf) && buf[j] == lab {
						j++
					}
					if j-i > bestCount {
						bestCount = j - i
						best = lab
					}
					i = j
				}
				next[v] = best
			}
		})
		cur, next = next, cur
	}
	return cur
}

// GALCC is the local clustering coefficient: rels among each node's
// undirected neighbour set over k*(k-1), forward rels counting.
func GALCC(g *chickpeas.Snapshot, directed bool) []float64 {
	n := int(g.NodeCount())
	out := gaFwd(directed)

	// Sorted forward-adjacency (CSR), built once; the triangle count
	// probes the smaller side of each intersection.
	off := make([]uint32, n+1)
	for v := range n {
		var d uint32
		for range g.Neighbors(uint32(v), out) {
			d++
		}
		off[v+1] = off[v] + d
	}
	adj := make([]uint32, off[n])
	for v := range n {
		s := off[v]
		p := s
		for w := range g.Neighbors(uint32(v), out) {
			adj[p] = w
			p++
		}
		slices.Sort(adj[s:p])
	}

	result := make([]float64, n)
	nWords := (n + 63) / 64
	parallel.For(n, func(lo, hi int) {
		// Per-chunk scratch: the N(v) membership bitset and neighbour
		// buffer, reused across the chunk's nodes.
		mark := make([]uint64, nWords)
		var nbrs []uint32
		for v := lo; v < hi; v++ {
			nbrs = nbrs[:0]
			for u := range g.Neighbors(uint32(v), chickpeas.Both) {
				marked := mark[u>>6]>>(u&63)&1 != 0
				if u != uint32(v) && !marked {
					mark[u>>6] |= 1 << (u & 63)
					nbrs = append(nbrs, u)
				}
			}
			k := len(nbrs)
			if k >= 2 {
				needSort := false
				for _, u := range nbrs {
					if int(off[u+1]-off[u]) > k {
						needSort = true
						break
					}
				}
				if needSort {
					slices.Sort(nbrs)
				}
				var rels uint64
				for _, u := range nbrs {
					uo := adj[off[u]:off[u+1]]
					if len(uo) <= k {
						for _, w := range uo {
							if w != u && mark[w>>6]>>(w&63)&1 != 0 {
								rels++
							}
						}
					} else {
						cursor := 0
						for _, w := range nbrs {
							if w == u {
								continue
							}
							found, pos := gaGallop(uo, cursor, w)
							cursor = pos
							if found {
								rels++
							}
						}
					}
				}
				result[v] = float64(rels) / (float64(k) * (float64(k) - 1.0))
			}
			for _, u := range nbrs {
				mark[u>>6] &^= 1 << (u & 63)
			}
		}
	})
	return result
}

// GASSSP is single-source shortest paths over forward rels (weight rel
// property, absent = 1.0); unreachable nodes get +Inf.
func GASSSP(g *chickpeas.Snapshot, source uint32, directed bool) []float64 {
	var wcol chickpeas.F64Col
	hasCol := false
	if c, ok := g.RelCol("weight"); ok {
		wcol = c.F64()
		hasCol = true
	}
	weight := func(_ chickpeas.NodeID, rel chickpeas.RelRef) float64 {
		if hasCol {
			if w, ok := wcol.Get(rel.Pos); ok {
				return w
			}
		}
		return 1.0
	}
	sp := g.Dijkstra(source, gaFwd(directed), chickpeas.MatchAll(), weight)
	n := g.NodeCount()
	out := make([]float64, n)
	for v := range n {
		if d, ok := sp.Distance(v); ok {
			out[v] = d
		} else {
			out[v] = math.Inf(1)
		}
	}
	return out
}

// biQ1 -- posting summary. Group messages before the cutoff (with
// content) by (year, isComment, lengthCategory); official RETURN order
// [year, isComment, messageCount, avg, sum, pct] with pct over ALL
// pre-cutoff messages.
func biQ1(g *chickpeas.Snapshot) ([][]any, error) {
	cutoff := dayFromCivil(2011, 12, 1)
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	lenCol, err := nodeI64Col(g, "length")
	if err != nil {
		return nil, err
	}
	yearCol, err := nodeI64Col(g, "year")
	if err != nil {
		return nil, err
	}
	contentCol, ok := g.Col("content")
	if !ok {
		return nil, fmt.Errorf("node column content missing")
	}
	contentStr := contentCol.Str()

	type key struct {
		year      int64
		isComment bool
		cat       int64
	}
	type agg struct {
		groups map[key][2]int64 // count, sumLength
		total  int64
	}
	total := int64(0)
	groups := map[key][2]int64{}
	for _, lc := range []struct {
		label     string
		isComment bool
	}{{"Post", false}, {"Comment", true}} {
		set, ok := g.NodesWithLabel(lc.label)
		if !ok {
			continue
		}
		ids := set.ToSlice()
		part := parallel.Fold(len(ids),
			func() agg { return agg{groups: map[key][2]int64{}} },
			func(acc agg, i int) agg {
				n := ids[i]
				if i64At(dayCol, n) >= cutoff {
					return acc
				}
				acc.total++
				if _, present := contentStr.ID(n); !present {
					return acc
				}
				l := i64At(lenCol, n)
				var cat int64
				switch {
				case l < 40:
					cat = 0
				case l < 80:
					cat = 1
				case l < 160:
					cat = 2
				default:
					cat = 3
				}
				k := key{i64At(yearCol, n), lc.isComment, cat}
				e := acc.groups[k]
				e[0]++
				e[1] += l
				acc.groups[k] = e
				return acc
			},
			func(a, b agg) agg {
				for k, v := range b.groups {
					e := a.groups[k]
					e[0] += v[0]
					e[1] += v[1]
					a.groups[k] = e
				}
				a.total += b.total
				return a
			})
		for k, v := range part.groups {
			e := groups[k]
			e[0] += v[0]
			e[1] += v[1]
			groups[k] = e
		}
		total += part.total
	}
	rows := make([][]any, 0, len(groups))
	for k, v := range groups {
		avg := float64(v[1]) / float64(v[0])
		pct := float64(v[0]) / float64(total)
		rows = append(rows, []any{k.year, k.isComment, k.cat, v[0], avg, v[1], pct})
	}
	return sortTruncate(rows, 0, func(a, b []any) bool {
		ac, bc := int64(0), int64(0)
		if a[1].(bool) {
			ac = 1
		}
		if b[1].(bool) {
			bc = 1
		}
		return cmpChain(
			cmpI64Desc(a[0].(int64), b[0].(int64)),
			cmpI64Asc(ac, bc),
			cmpI64Asc(a[2].(int64), b[2].(int64)),
		)
	}), nil
}

// biQ2 -- tag evolution. Messages tagged with MusicalArtist tags in two
// consecutive 100-day windows from 2012-06-01; [name, w1, w2, |diff|],
// diff desc / name asc, top 100. Every qualifying tag emits a row.
func biQ2(g *chickpeas.Snapshot) ([][]any, error) {
	date0 := dayFromCivil(2012, 6, 1)
	target, ok := nodeByName(g, "TagClass", "MusicalArtist")
	if !ok {
		return [][]any{}, nil
	}
	qualifying := map[chickpeas.NodeID]bool{}
	for t := range g.Neighbors(target, chickpeas.Incoming, "HAS_TYPE") {
		qualifying[t] = true
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	w1lo, w1hi := date0, date0+100
	w2lo, w2hi := date0+100, date0+200
	type winCounts struct{ c1, c2 map[chickpeas.NodeID]int64 }
	c1 := map[chickpeas.NodeID]int64{}
	c2 := map[chickpeas.NodeID]int64{}
	for _, label := range []string{"Post", "Comment"} {
		set, ok := g.NodesWithLabel(label)
		if !ok {
			continue
		}
		ids := set.ToSlice()
		part := parallel.Fold(len(ids),
			func() winCounts {
				return winCounts{map[chickpeas.NodeID]int64{}, map[chickpeas.NodeID]int64{}}
			},
			func(acc winCounts, i int) winCounts {
				msg := ids[i]
				day := i64At(dayCol, msg)
				in1 := w1lo <= day && day < w1hi
				in2 := w2lo <= day && day < w2hi
				if !in1 && !in2 {
					return acc
				}
				for t := range g.Neighbors(msg, chickpeas.Outgoing, "HAS_TAG") {
					if qualifying[t] {
						if in1 {
							acc.c1[t]++
						} else {
							acc.c2[t]++
						}
					}
				}
				return acc
			},
			func(a, b winCounts) winCounts {
				for k, v := range b.c1 {
					a.c1[k] += v
				}
				for k, v := range b.c2 {
					a.c2[k] += v
				}
				return a
			})
		for k, v := range part.c1 {
			c1[k] += v
		}
		for k, v := range part.c2 {
			c2[k] += v
		}
	}
	rows := make([][]any, 0, len(qualifying))
	for t := range qualifying {
		n1, n2 := c1[t], c2[t]
		diff := n1 - n2
		if diff < 0 {
			diff = -diff
		}
		rows = append(rows, []any{strAt(g, t, "name"), n1, n2, diff})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[3].(int64), b[3].(int64)),
			cmpStrAsc(a[0].(string), b[0].(string)),
		)
	}), nil
}

// biQ5 -- most active posters of a topic (Abbas_I_of_Persia). Score
// creators of tagged messages by 1*msgs + 2*replies + 10*likes;
// [personId, replyCount, likeCount, messageCount, score], top 100.
func biQ5(g *chickpeas.Snapshot) ([][]any, error) {
	target, ok := nodeByName(g, "Tag", "Abbas_I_of_Persia")
	if !ok {
		return [][]any{}, nil
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	type score struct{ m, r, l int64 }
	agg := map[chickpeas.NodeID]score{}
	for msg := range g.Neighbors(target, chickpeas.Incoming, "HAS_TAG") {
		var likes, replies int64
		for range g.Neighbors(msg, chickpeas.Incoming, "LIKES") {
			likes++
		}
		for range g.Neighbors(msg, chickpeas.Incoming, "REPLY_OF") {
			replies++
		}
		for person := range g.Neighbors(msg, chickpeas.Outgoing, "HAS_CREATOR") {
			e := agg[person]
			e.m++
			e.r += replies
			e.l += likes
			agg[person] = e
		}
	}
	rows := make([][]any, 0, len(agg))
	for p, s := range agg {
		rows = append(rows, []any{i64At(idCol, p), s.r, s.l, s.m, s.m + 2*s.r + 10*s.l})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[4].(int64), b[4].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ6 -- most authoritative users on a topic (Arnold_Schwarzenegger).
// authority(person1) = sum over distinct likers of person1's tagged
// messages of the likes those likers received on their own messages;
// [personId, authorityScore], top 100.
func biQ6(g *chickpeas.Snapshot) ([][]any, error) {
	target, ok := nodeByName(g, "Tag", "Arnold_Schwarzenegger")
	if !ok {
		return [][]any{}, nil
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	p1ToP2 := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	for m1 := range g.Neighbors(target, chickpeas.Incoming, "HAS_TAG") {
		var likers []chickpeas.NodeID
		for liker := range g.Neighbors(m1, chickpeas.Incoming, "LIKES") {
			likers = append(likers, liker)
		}
		if len(likers) == 0 {
			continue
		}
		for p1 := range g.Neighbors(m1, chickpeas.Outgoing, "HAS_CREATOR") {
			set := p1ToP2[p1]
			if set == nil {
				set = map[chickpeas.NodeID]bool{}
				p1ToP2[p1] = set
			}
			for _, l := range likers {
				set[l] = true
			}
		}
	}
	likerScore := map[chickpeas.NodeID]int64{}
	for _, p2set := range p1ToP2 {
		for p2 := range p2set {
			if _, done := likerScore[p2]; done {
				continue
			}
			var s int64
			for m2 := range g.Neighbors(p2, chickpeas.Incoming, "HAS_CREATOR") {
				for range g.Neighbors(m2, chickpeas.Incoming, "LIKES") {
					s++
				}
			}
			likerScore[p2] = s
		}
	}
	rows := make([][]any, 0, len(p1ToP2))
	for p1, p2set := range p1ToP2 {
		var s int64
		for p2 := range p2set {
			s += likerScore[p2]
		}
		rows = append(rows, []any{i64At(idCol, p1), s})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[1].(int64), b[1].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ7 -- related topics (Enrique_Iglesias). Distinct comments replying
// to tagged messages, not themselves tagged, counted per other tag;
// [name, count], count desc / name asc, top 100.
func biQ7(g *chickpeas.Snapshot) ([][]any, error) {
	target, ok := nodeByName(g, "Tag", "Enrique_Iglesias")
	if !ok {
		return [][]any{}, nil
	}
	related := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	for msg := range g.Neighbors(target, chickpeas.Incoming, "HAS_TAG") {
		for comment := range g.Neighbors(msg, chickpeas.Incoming, "REPLY_OF") {
			var ctags []chickpeas.NodeID
			hasTarget := false
			for t := range g.Neighbors(comment, chickpeas.Outgoing, "HAS_TAG") {
				if t == target {
					hasTarget = true
				}
				ctags = append(ctags, t)
			}
			if hasTarget {
				continue
			}
			for _, rt := range ctags {
				set := related[rt]
				if set == nil {
					set = map[chickpeas.NodeID]bool{}
					related[rt] = set
				}
				set[comment] = true
			}
		}
	}
	rows := make([][]any, 0, len(related))
	for rt, cs := range related {
		rows = append(rows, []any{strAt(g, rt, "name"), int64(len(cs))})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[1].(int64), b[1].(int64)),
			cmpStrAsc(a[0].(string), b[0].(string)),
		)
	}), nil
}

// biQ8 -- central person for a tag (Che_Guevara, 2011-07-20..25
// exclusive). score = 100*interest + tagged messages in window;
// friendsScore sums friends' scores; [personId, score, friendsScore],
// (score+friendsScore) desc / id asc, top 100.
func biQ8(g *chickpeas.Snapshot) ([][]any, error) {
	tag, ok := nodeByName(g, "Tag", "Che_Guevara")
	if !ok {
		return [][]any{}, nil
	}
	startDay, endDay := dayFromCivil(2011, 7, 20), dayFromCivil(2011, 7, 25)
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	score := map[chickpeas.NodeID]int64{}
	for p := range g.Neighbors(tag, chickpeas.Incoming, "HAS_INTEREST") {
		score[p] += 100
	}
	for msg := range g.Neighbors(tag, chickpeas.Incoming, "HAS_TAG") {
		day := i64At(dayCol, msg)
		if day > startDay && day < endDay {
			for creator := range g.Neighbors(msg, chickpeas.Outgoing, "HAS_CREATOR") {
				score[creator]++
			}
		}
	}
	rows := make([][]any, 0, len(score))
	for p, s := range score {
		var fs int64
		for f := range g.Neighbors(p, chickpeas.Both, "KNOWS") {
			fs += score[f]
		}
		rows = append(rows, []any{i64At(idCol, p), s, fs})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[1].(int64)+a[2].(int64), b[1].(int64)+b[2].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ9 -- top thread initiators (2011-10-01..15 inclusive). Per person:
// posts in window and messages in those posts' reply trees (in window,
// pruned past endDay); [personId, threadCount, messageCount],
// messageCount desc / id asc, top 100.
func biQ9(g *chickpeas.Snapshot) ([][]any, error) {
	startDay, endDay := dayFromCivil(2011, 10, 1), dayFromCivil(2011, 10, 15)
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	type tm struct{ threads, msgs int64 }
	perPerson := map[chickpeas.NodeID]tm{}
	posts, ok := g.NodesWithLabel("Post")
	if ok {
		for post := range posts.Iter() {
			pd := i64At(dayCol, post)
			if pd < startDay || pd > endDay {
				continue
			}
			creator, ok := creatorOf(g, post)
			if !ok {
				continue
			}
			var msgs int64
			stack := []chickpeas.NodeID{post}
			for len(stack) > 0 {
				n := stack[len(stack)-1]
				stack = stack[:len(stack)-1]
				d := i64At(dayCol, n)
				if d > endDay {
					continue
				}
				if d >= startDay {
					msgs++
				}
				for c := range g.Neighbors(n, chickpeas.Incoming, "REPLY_OF") {
					stack = append(stack, c)
				}
			}
			e := perPerson[creator]
			e.threads++
			e.msgs += msgs
			perPerson[creator] = e
		}
	}
	rows := make([][]any, 0, len(perPerson))
	for p, e := range perPerson {
		rows = append(rows, []any{i64At(idCol, p), e.threads, e.msgs})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[2].(int64), b[2].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ11 -- friend triangles (India, 2012-09-29..2013-01-01 inclusive).
// Count knows-triangles among persons of the country where every edge
// was created in the window; [[count]].
func biQ11(g *chickpeas.Snapshot) ([][]any, error) {
	country, ok := nodeByName(g, "Country", "India")
	if !ok {
		return [][]any{}, nil
	}
	startDay, endDay := dayFromCivil(2012, 9, 29), dayFromCivil(2013, 1, 1)
	kdCol, ok := g.RelCol("creationDate")
	if !ok {
		return nil, fmt.Errorf("rel column creationDate missing")
	}
	kd := kdCol.I64()
	inCountry := personsOfCountry(g, country)
	adj := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	for a := range inCountry {
		for e := range g.Rels(a, chickpeas.Both, "KNOWS") {
			if !inCountry[e.Neighbor] {
				continue
			}
			ms, ok := kd.Get(e.Pos)
			if !ok {
				continue
			}
			day := floorDiv(ms, msPerDay)
			if day >= startDay && day <= endDay {
				set := adj[a]
				if set == nil {
					set = map[chickpeas.NodeID]bool{}
					adj[a] = set
				}
				set[e.Neighbor] = true
			}
		}
	}
	var count int64
	for a, nbrsA := range adj {
		for b := range nbrsA {
			if b <= a {
				continue
			}
			for c := range adj[b] {
				if c > b && nbrsA[c] {
					count++
				}
			}
		}
	}
	return [][]any{{count}}, nil
}

// biQ12 -- message-count histogram (len<20, after 2010-07-22, root
// language ar/hu). Persons histogrammed by qualifying-message count
// (zero bucket included); [messageCount, personCount], personCount desc
// / messageCount desc.
func biQ12(g *chickpeas.Snapshot) ([][]any, error) {
	minDay := dayFromCivil(2010, 7, 22)
	const lenThr = 20
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	lenCol, err := nodeI64Col(g, "length")
	if err != nil {
		return nil, err
	}
	contentCol, ok := g.Col("content")
	if !ok {
		return nil, fmt.Errorf("node column content missing")
	}
	contentStr := contentCol.Str()
	langCol, ok := g.Col("language")
	if !ok {
		return nil, fmt.Errorf("node column language missing")
	}
	langStr := langCol.Str()
	langIDs := map[uint32]bool{}
	for _, l := range []string{"ar", "hu"} {
		if id, ok := g.Atoms().ID(l); ok {
			langIDs[id] = true
		}
	}
	var roots chickpeas.RootsVia
	if rt, ok := g.RelType("REPLY_OF"); ok {
		roots = g.RootsVia(rt, chickpeas.Outgoing)
	}
	rootOf := func(n chickpeas.NodeID) chickpeas.NodeID {
		if roots == nil {
			return n
		}
		return roots[n]
	}

	counts := map[chickpeas.NodeID]int64{}
	for _, label := range []string{"Post", "Comment"} {
		set, ok := g.NodesWithLabel(label)
		if !ok {
			continue
		}
		ids := set.ToSlice()
		part := parallel.Fold(len(ids),
			func() map[chickpeas.NodeID]int64 { return map[chickpeas.NodeID]int64{} },
			func(acc map[chickpeas.NodeID]int64, i int) map[chickpeas.NodeID]int64 {
				msg := ids[i]
				if i64At(dayCol, msg) <= minDay {
					return acc
				}
				if _, present := contentStr.ID(msg); !present {
					return acc
				}
				if i64At(lenCol, msg) >= lenThr {
					return acc
				}
				lid, ok := langStr.ID(rootOf(msg))
				if !ok || !langIDs[lid] {
					return acc
				}
				if creator, ok := creatorOf(g, msg); ok {
					acc[creator]++
				}
				return acc
			},
			func(a, b map[chickpeas.NodeID]int64) map[chickpeas.NodeID]int64 {
				for k, v := range b {
					a[k] += v
				}
				return a
			})
		for k, v := range part {
			counts[k] += v
		}
	}
	totalPersons := int64(0)
	if ps, ok := g.NodesWithLabel("Person"); ok {
		totalPersons = int64(ps.Len())
	}
	hist := map[int64]int64{}
	for _, c := range counts {
		hist[c]++
	}
	hist[0] = totalPersons - int64(len(counts))
	rows := make([][]any, 0, len(hist))
	for mc, pc := range hist {
		rows = append(rows, []any{mc, pc})
	}
	return sortTruncate(rows, 0, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[1].(int64), b[1].(int64)),
			cmpI64Desc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ13 -- zombies in France (before 2013-01-01). Low-activity persons
// (under one message per month since account creation) scored by the
// share of their likes coming from other zombies; [personId,
// zombieLikeCount, totalLikeCount], likeRatio desc / id asc, top 100.
func biQ13(g *chickpeas.Snapshot) ([][]any, error) {
	country, ok := nodeByName(g, "Country", "France")
	if !ok {
		return [][]any{}, nil
	}
	endDay := dayFromCivil(2013, 1, 1)
	endYM := int64(2013*12 + 1)
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	dayCol, err := nodeI64Col(g, "day")
	if err != nil {
		return nil, err
	}
	pdayCol, err := nodeI64Col(g, "pday")
	if err != nil {
		return nil, err
	}
	pymCol, err := nodeI64Col(g, "pym")
	if err != nil {
		return nil, err
	}
	persons, _ := g.NodesWithLabel("Person")
	zombies := map[chickpeas.NodeID]bool{}
	for city := range g.Neighbors(country, chickpeas.Incoming, "IS_PART_OF") {
		for p := range g.Neighbors(city, chickpeas.Incoming, "IS_LOCATED_IN") {
			if persons == nil || !persons.Contains(p) {
				continue
			}
			if i64At(pdayCol, p) >= endDay {
				continue
			}
			var mcount int64
			for m := range g.Neighbors(p, chickpeas.Incoming, "HAS_CREATOR") {
				if i64At(dayCol, m) < endDay {
					mcount++
				}
			}
			months := endYM - i64At(pymCol, p) + 1
			if months > 0 && mcount < months {
				zombies[p] = true
			}
		}
	}
	rows := make([][]any, 0, len(zombies))
	for z := range zombies {
		var zlc, tlc int64
		for m := range g.Neighbors(z, chickpeas.Incoming, "HAS_CREATOR") {
			for liker := range g.Neighbors(m, chickpeas.Incoming, "LIKES") {
				if i64At(pdayCol, liker) < endDay {
					tlc++
				}
				if zombies[liker] {
					zlc++
				}
			}
		}
		rows = append(rows, []any{i64At(idCol, z), zlc, tlc})
	}
	ratio := func(r []any) float64 {
		if r[2].(int64) == 0 {
			return 0
		}
		return float64(r[1].(int64)) / float64(r[2].(int64))
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpF64Desc(ratio(a), ratio(b)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ14 -- international dialog (Chile -> Argentina). Per city of
// country1, the best-scoring knows-pair (p1 in city, p2 in country2)
// where score rewards reply/like interaction kinds; [p1Id, p2Id,
// cityName, score], score desc / p1 asc / p2 asc, top 100.
func biQ14(g *chickpeas.Snapshot) ([][]any, error) {
	country1, ok1 := nodeByName(g, "Country", "Chile")
	country2, ok2 := nodeByName(g, "Country", "Argentina")
	if !ok1 || !ok2 {
		return [][]any{}, nil
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	commentedOn := func(p chickpeas.NodeID) map[chickpeas.NodeID]bool {
		s := map[chickpeas.NodeID]bool{}
		for msg := range g.Neighbors(p, chickpeas.Incoming, "HAS_CREATOR") {
			for parent := range g.Neighbors(msg, chickpeas.Outgoing, "REPLY_OF") {
				if cr, ok := creatorOf(g, parent); ok {
					s[cr] = true
				}
			}
		}
		return s
	}
	likedCreators := func(p chickpeas.NodeID) map[chickpeas.NodeID]bool {
		s := map[chickpeas.NodeID]bool{}
		for msg := range g.Neighbors(p, chickpeas.Outgoing, "LIKES") {
			if cr, ok := creatorOf(g, msg); ok {
				s[cr] = true
			}
		}
		return s
	}
	inC2 := map[chickpeas.NodeID]bool{}
	coC2 := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	lcC2 := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	for city := range g.Neighbors(country2, chickpeas.Incoming, "IS_PART_OF") {
		for p := range g.Neighbors(city, chickpeas.Incoming, "IS_LOCATED_IN") {
			if inC2[p] {
				continue
			}
			inC2[p] = true
			coC2[p] = commentedOn(p)
			lcC2[p] = likedCreators(p)
		}
	}
	var rows [][]any
	for city := range g.Neighbors(country1, chickpeas.Incoming, "IS_PART_OF") {
		cityName := strAt(g, city, "name")
		type cand struct {
			score, pa, pb int64
			found         bool
		}
		var best cand
		for p1 := range g.Neighbors(city, chickpeas.Incoming, "IS_LOCATED_IN") {
			p1co := commentedOn(p1)
			p1lc := likedCreators(p1)
			for p2 := range g.Neighbors(p1, chickpeas.Both, "KNOWS") {
				if !inC2[p2] {
					continue
				}
				var score int64
				if p1co[p2] {
					score += 4
				}
				if coC2[p2][p1] {
					score += 1
				}
				if p1lc[p2] {
					score += 10
				}
				if lcC2[p2][p1] {
					score += 1
				}
				pa, pb := i64At(idCol, p1), i64At(idCol, p2)
				// Keep the incumbent unless the candidate wins
				// (score desc, p1 id asc, p2 id asc).
				if best.found && !cmpChain(
					cmpI64Desc(score, best.score),
					cmpI64Asc(pa, best.pa),
					cmpI64Asc(pb, best.pb),
				) {
					continue
				}
				best = cand{score, pa, pb, true}
			}
		}
		if best.found {
			rows = append(rows, []any{best.pa, best.pb, cityName, best.score})
		}
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[3].(int64), b[3].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
			cmpI64Asc(a[1].(int64), b[1].(int64)),
		)
	}), nil
}

// biQ18 -- friend recommendation (Frank_Sinatra). Ordered pairs of
// tag-interested persons, not directly known, by distinct mutual
// friends; [p1Id, p2Id, mutualFriendCount], count desc / p1 asc / p2
// asc, top 20.
func biQ18(g *chickpeas.Snapshot) ([][]any, error) {
	tag, ok := nodeByName(g, "Tag", "Frank_Sinatra")
	if !ok {
		return [][]any{}, nil
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	var interested []chickpeas.NodeID
	endpoints := nodeset.New()
	for p := range g.Neighbors(tag, chickpeas.Incoming, "HAS_INTEREST") {
		interested = append(interested, p)
		endpoints.Insert(p)
	}
	pairs := g.CommonNeighborCounts(interested, chickpeas.Both, g.Match("KNOWS"), endpoints)
	knowsOf := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	var rows [][]any
	for _, pr := range pairs {
		if pr.Source == pr.Target {
			continue
		}
		known := knowsOf[pr.Source]
		if known == nil {
			known = map[chickpeas.NodeID]bool{}
			for f := range g.Neighbors(pr.Source, chickpeas.Both, "KNOWS") {
				known[f] = true
			}
			knowsOf[pr.Source] = known
		}
		if known[pr.Target] {
			continue
		}
		rows = append(rows, []any{i64At(idCol, pr.Source), i64At(idCol, pr.Target), int64(pr.Count)})
	}
	return sortTruncate(rows, 20, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[2].(int64), b[2].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
			cmpI64Asc(a[1].(int64), b[1].(int64)),
		)
	}), nil
}

// biQ19 -- interaction path between cities (669 <-> 648). Weighted
// shortest knows-path per (p1 in city1, p2 in city2) with weight
// 1/interactions; [p1Id, p2Id, totalWeight], weight asc / p1 asc / p2
// asc, top 20. The interaction map is built in the untimed prepare
// phase, matching the rcp-native harness (its timer sees only the
// per-pair searches).
func biQ19(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	interaction := buildInteractionMap(g)
	return func() ([][]any, error) {
		city1, ok1 := nodeByID(g, "City", 669)
		city2, ok2 := nodeByID(g, "City", 648)
		if !ok1 || !ok2 {
			return [][]any{}, nil
		}
		weight := func(from chickpeas.NodeID, rel chickpeas.RelRef) float64 {
			if n := interaction[pairKey(from, rel.Neighbor)]; n > 0 {
				return 1.0 / float64(n)
			}
			return inf
		}
		var c2 []chickpeas.NodeID
		for p := range g.Neighbors(city2, chickpeas.Incoming, "IS_LOCATED_IN") {
			c2 = append(c2, p)
		}
		m := g.Match("KNOWS")
		rows := chickpeas.ParNeighborFold(g, city1, chickpeas.Incoming, g.Match("IS_LOCATED_IN"),
			func() [][]any { return nil },
			func(acc [][]any, p1 chickpeas.NodeID) [][]any {
				for _, p2 := range c2 {
					if d, ok := g.WeightedShortestPath(p1, p2, chickpeas.Both, m, weight); ok && finite(d) {
						acc = append(acc, []any{i64At(idCol, p1), i64At(idCol, p2), d})
					}
				}
				return acc
			},
			func(a, b [][]any) [][]any { return append(a, b...) })
		return sortTruncate(rows, 20, func(a, b []any) bool {
			return cmpChain(
				cmpF64Asc(a[2].(float64), b[2].(float64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
				cmpI64Asc(a[1].(int64), b[1].(int64)),
			)
		}), nil
	}, nil
}

// biQ20 -- recruitment (Falcon_Air -> person 66). Weighted shortest
// knows-path from each company employee to the target where edge weight
// is min |classYear difference|+1 over shared universities; [p1Id,
// pathWeight], weight asc / id asc, top 20. The study records and the
// cohort weight map are built in the untimed prepare phase, matching
// the rcp-native harness.
func biQ20(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	cyCol, ok := g.RelCol("classYear")
	if !ok {
		return nil, fmt.Errorf("rel column classYear missing")
	}
	cy := cyCol.I64()
	studyat := map[chickpeas.NodeID][]studyRecord{}
	if persons, ok := g.NodesWithLabel("Person"); ok {
		for p := range persons.Iter() {
			var recs []studyRecord
			for r := range g.Rels(p, chickpeas.Outgoing, "STUDY_AT") {
				year, _ := cy.Get(r.Pos)
				recs = append(recs, studyRecord{r.Neighbor, year})
			}
			if len(recs) > 0 {
				studyat[p] = recs
			}
		}
	}
	wm := map[interactionKey]float64{}
	for a, sa := range studyat {
		for b := range g.Neighbors(a, chickpeas.Both, "KNOWS") {
			if b <= a {
				continue
			}
			sb, ok := studyat[b]
			if !ok {
				continue
			}
			best := int64(-1)
			for _, ra := range sa {
				for _, rb := range sb {
					if ra.uni != rb.uni {
						continue
					}
					d := ra.year - rb.year
					if d < 0 {
						d = -d
					}
					if best < 0 || d < best {
						best = d
					}
				}
			}
			if best >= 0 {
				wm[interactionKey{a, b}] = float64(best + 1)
			}
		}
	}
	return func() ([][]any, error) {
		company, ok1 := nodeByName(g, "Company", "Falcon_Air")
		person2, ok2 := nodeByID(g, "Person", 66)
		if !ok1 || !ok2 {
			return [][]any{}, nil
		}
		weight := func(from chickpeas.NodeID, rel chickpeas.RelRef) float64 {
			if w, ok := wm[pairKey(from, rel.Neighbor)]; ok {
				return w
			}
			return inf
		}
		m := g.Match("KNOWS")
		var rows [][]any
		for p1 := range g.Neighbors(company, chickpeas.Incoming, "WORK_AT") {
			if p1 == person2 {
				continue
			}
			sp := g.DijkstraTo(p1, person2, chickpeas.Both, m, weight)
			if d, ok := sp.Distance(person2); ok && finite(d) {
				rows = append(rows, []any{i64At(idCol, p1), d})
			}
		}
		return sortTruncate(rows, 20, func(a, b []any) bool {
			return cmpChain(
				cmpF64Asc(a[1].(float64), b[1].(float64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// biQ3 -- popular topics in a country (Burma, MusicalArtist). Forums
// moderated from the country counted by distinct reply-tree messages
// carrying a class tag; [forumId, title, forumCreationDate(ms), modId,
// messageCount], count desc / forumId asc, top 20. The creationDate
// column is epoch-ms against an epoch-day ref (norm col2:msday).
func biQ3(g *chickpeas.Snapshot) ([][]any, error) {
	country, ok1 := nodeByName(g, "Country", "Burma")
	tc, ok2 := nodeByName(g, "TagClass", "MusicalArtist")
	if !ok1 || !ok2 {
		return [][]any{}, nil
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	cdCol, err := nodeI64Col(g, "creationDate")
	if err != nil {
		return nil, err
	}
	classTags := map[chickpeas.NodeID]bool{}
	for t := range g.Neighbors(tc, chickpeas.Incoming, "HAS_TYPE") {
		classTags[t] = true
	}
	hasClassTag := func(msg chickpeas.NodeID) bool {
		for t := range g.Neighbors(msg, chickpeas.Outgoing, "HAS_TAG") {
			if classTags[t] {
				return true
			}
		}
		return false
	}
	var rows [][]any
	for city := range g.Neighbors(country, chickpeas.Incoming, "IS_PART_OF") {
		for person := range g.Neighbors(city, chickpeas.Incoming, "IS_LOCATED_IN") {
			for forum := range g.Neighbors(person, chickpeas.Incoming, "HAS_MODERATOR") {
				msgs := map[chickpeas.NodeID]bool{}
				for post := range g.Neighbors(forum, chickpeas.Outgoing, "CONTAINER_OF") {
					stack := []chickpeas.NodeID{post}
					for len(stack) > 0 {
						n := stack[len(stack)-1]
						stack = stack[:len(stack)-1]
						if hasClassTag(n) {
							msgs[n] = true
						}
						for c := range g.Neighbors(n, chickpeas.Incoming, "REPLY_OF") {
							stack = append(stack, c)
						}
					}
				}
				if len(msgs) > 0 {
					rows = append(rows, []any{
						i64At(idCol, forum), strAt(g, forum, "title"),
						i64At(cdCol, forum), i64At(idCol, person), int64(len(msgs)),
					})
				}
			}
		}
	}
	return sortTruncate(rows, 20, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[4].(int64), b[4].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ4 -- top message creators (forums created after 2010-01-29). The
// top-100 forums by largest single-country member cohort, then all
// their members ranked by messages created in those forums' reply
// trees; [personId, messageCount], count desc / id asc, top 100.
func biQ4(g *chickpeas.Snapshot) ([][]any, error) {
	afterDay := dayFromCivil(2010, 1, 29)
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	fdayCol, err := nodeI64Col(g, "fday")
	if err != nil {
		return nil, err
	}
	var forums []chickpeas.NodeID
	if fs, ok := g.NodesWithLabel("Forum"); ok {
		for f := range fs.Iter() {
			if i64At(fdayCol, f) > afterDay {
				forums = append(forums, f)
			}
		}
	}
	top := g.NeighborGroups(forums, g.Match("HAS_MEMBER"), chickpeas.Outgoing).
		Project(
			chickpeas.Step{Dir: chickpeas.Outgoing, RelType: "IS_LOCATED_IN"},
			chickpeas.Step{Dir: chickpeas.Outgoing, RelType: "IS_PART_OF"},
		).
		TopBySize(100, "id")
	members := map[chickpeas.NodeID]bool{}
	for _, s := range top {
		for m := range g.Neighbors(s.Source, chickpeas.Outgoing, "HAS_MEMBER") {
			members[m] = true
		}
	}
	msgCount := map[chickpeas.NodeID]int64{}
	var stack []chickpeas.NodeID
	for _, s := range top {
		for post := range g.Neighbors(s.Source, chickpeas.Outgoing, "CONTAINER_OF") {
			stack = append(stack, post)
		}
		for len(stack) > 0 {
			n := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			if creator, ok := creatorOf(g, n); ok && members[creator] {
				msgCount[creator]++
			}
			for c := range g.Neighbors(n, chickpeas.Incoming, "REPLY_OF") {
				stack = append(stack, c)
			}
		}
	}
	rows := make([][]any, 0, len(members))
	for p := range members {
		rows = append(rows, []any{i64At(idCol, p), msgCount[p]})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[1].(int64), b[1].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ10 -- experts in social circle (person 3470, China, MusicalArtist,
// knows-distance 3..4). Distinct tagged messages per (expert, tag) where
// the message carries any class tag; [personId, tagName, messageCount],
// count desc / name asc / id asc, top 100.
func biQ10(g *chickpeas.Snapshot) ([][]any, error) {
	start, ok := nodeByID(g, "Person", 3470)
	if !ok {
		return [][]any{}, nil
	}
	const minDist, maxDist = 3, 4
	country, ok1 := nodeByName(g, "Country", "China")
	tc, ok2 := nodeByName(g, "TagClass", "MusicalArtist")
	if !ok1 || !ok2 {
		return [][]any{}, nil
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	dist := g.BFSDistances(start, chickpeas.Both, g.Match("KNOWS"), maxDist)
	inCountry := personsOfCountry(g, country)
	classTags := map[chickpeas.NodeID]bool{}
	for t := range g.Neighbors(tc, chickpeas.Incoming, "HAS_TYPE") {
		classTags[t] = true
	}
	type expertTag struct{ expert, tag chickpeas.NodeID }
	counts := map[expertTag]map[chickpeas.NodeID]bool{}
	for expert, d := range dist {
		if d < minDist || d > maxDist || !inCountry[expert] {
			continue
		}
		for msg := range g.Neighbors(expert, chickpeas.Incoming, "HAS_CREATOR") {
			var tags []chickpeas.NodeID
			anyClass := false
			for t := range g.Neighbors(msg, chickpeas.Outgoing, "HAS_TAG") {
				if classTags[t] {
					anyClass = true
				}
				tags = append(tags, t)
			}
			if !anyClass {
				continue
			}
			for _, t := range tags {
				k := expertTag{expert, t}
				set := counts[k]
				if set == nil {
					set = map[chickpeas.NodeID]bool{}
					counts[k] = set
				}
				set[msg] = true
			}
		}
	}
	rows := make([][]any, 0, len(counts))
	for k, msgs := range counts {
		rows = append(rows, []any{i64At(idCol, k.expert), strAt(g, k.tag, "name"), int64(len(msgs))})
	}
	return sortTruncate(rows, 100, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[2].(int64), b[2].(int64)),
			cmpStrAsc(a[1].(string), b[1].(string)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// biQ15 -- weighted interaction path (persons 14 -> 16, forums created
// 2010-11-01..2010-12-01). Reply interactions whose thread forum falls
// in the window weight the knows graph (post reply 1.0, comment reply
// 0.5); edge weight 1/(w+1); [[cost]] or [[-1.0]] when unreachable.
func biQ15(g *chickpeas.Snapshot) ([][]any, error) {
	src, ok1 := nodeByID(g, "Person", 14)
	tgt, ok2 := nodeByID(g, "Person", 16)
	if !ok1 || !ok2 {
		return [][]any{{-1.0}}, nil
	}
	startDay, endDay := dayFromCivil(2010, 11, 1), dayFromCivil(2010, 12, 1)
	fdayCol, err := nodeI64Col(g, "fday")
	if err != nil {
		return nil, err
	}
	posts, _ := g.NodesWithLabel("Post")
	comments, ok := g.NodesWithLabel("Comment")
	replyOf, okRt := g.RelType("REPLY_OF")
	w := map[interactionKey]float64{}
	if ok && okRt {
		roots := g.RootsVia(replyOf, chickpeas.Outgoing)
		ids := comments.ToSlice()
		w = parallel.Fold(len(ids),
			func() map[interactionKey]float64 { return map[interactionKey]float64{} },
			func(acc map[interactionKey]float64, i int) map[interactionKey]float64 {
				c := ids[i]
				parent, ok := g.FirstNeighbor(c, chickpeas.Outgoing, "REPLY_OF")
				if !ok {
					return acc
				}
				cc, ok1 := creatorOf(g, c)
				pc, ok2 := creatorOf(g, parent)
				if !ok1 || !ok2 || cc == pc {
					return acc
				}
				root := roots[c]
				forum, ok := g.FirstNeighbor(root, chickpeas.Incoming, "CONTAINER_OF")
				if !ok {
					return acc
				}
				fday := i64At(fdayCol, forum)
				if fday >= startDay && fday <= endDay {
					contrib := 0.5
					if posts != nil && posts.Contains(parent) {
						contrib = 1.0
					}
					acc[pairKey(cc, pc)] += contrib
				}
				return acc
			},
			func(a, b map[interactionKey]float64) map[interactionKey]float64 {
				for k, v := range b {
					a[k] += v
				}
				return a
			})
	}
	weight := func(from chickpeas.NodeID, rel chickpeas.RelRef) float64 {
		return 1.0 / (w[pairKey(from, rel.Neighbor)] + 1.0)
	}
	sp := g.DijkstraTo(src, tgt, chickpeas.Both, g.Match("KNOWS"), weight)
	if d, ok := sp.Distance(tgt); ok && finite(d) {
		return [][]any{{d}}, nil
	}
	return [][]any{{-1.0}}, nil
}

// biQ16 -- fake news detection (Meryl_Streep@2012-09-16 AND
// Hank_Williams@2012-05-08, maxKnows 4). Persons qualifying for both
// params; [personId, countA, countB], (a+b) desc / id asc, top 20.
// The official params select zero rows at SF1 (the ref is empty).
func biQ16(g *chickpeas.Snapshot) ([][]any, error) {
	ra, err := biQ16Param(g, "Meryl_Streep", dayFromCivil(2012, 9, 16), 4)
	if err != nil {
