// biQ17 -- information propagation (Slavoj_Žižek, delta 4h). Distinct
// message2 per person1 where person1's tagged message1 sits in forum1;
// a forum1 member p2 posted a tagged comment replying to tagged
// message2 (by another forum1 member p3) in a different forum2, more
// than delta after message1, with person1 not a member of forum2;
// [personId, messageCount], count desc / id asc, top 10.
func biQ17(g *chickpeas.Snapshot) ([][]any, error) {
	tag, ok := nodeByName(g, "Tag", "Slavoj_Žižek")
	if !ok {
		return [][]any{}, nil
	}
	const deltaMS = 4 * 3_600_000
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	msCol, err := nodeI64Col(g, "ms")
	if err != nil {
		return nil, err
	}
	var roots chickpeas.RootsVia
	if rt, ok := g.RelType("REPLY_OF"); ok {
		roots = g.RootsVia(rt, chickpeas.Outgoing)
	}
	forumOf := func(m chickpeas.NodeID) (chickpeas.NodeID, bool) {
		root := m
		if roots != nil {
			root = roots[m]
		}
		return g.FirstNeighbor(root, chickpeas.Incoming, "CONTAINER_OF")
	}
	var tagged []chickpeas.NodeID
	taggedSet := map[chickpeas.NodeID]bool{}
	for m := range g.Neighbors(tag, chickpeas.Incoming, "HAS_TAG") {
		tagged = append(tagged, m)
		taggedSet[m] = true
	}
	type m1Rec struct {
		p1  chickpeas.NodeID
		ms1 int64
	}
	type candRec struct {
		p2, p3, msg2, f2 chickpeas.NodeID
		ms2              int64
	}
	m1ByForum := map[chickpeas.NodeID][]m1Rec{}
	var cands []candRec
	relevant := map[chickpeas.NodeID]bool{}
	for _, m := range tagged {
		if p1, ok := creatorOf(g, m); ok {
			if f1, ok := forumOf(m); ok {
				m1ByForum[f1] = append(m1ByForum[f1], m1Rec{p1, i64At(msCol, m)})
				relevant[f1] = true
			}
		}
		msg2, ok := g.FirstNeighbor(m, chickpeas.Outgoing, "REPLY_OF")
		if !ok || !taggedSet[msg2] {
			continue
		}
		p2, ok1 := creatorOf(g, m)
		p3, ok2 := creatorOf(g, msg2)
		f2, ok3 := forumOf(msg2)
		if ok1 && ok2 && ok3 {
			cands = append(cands, candRec{p2, p3, msg2, f2, i64At(msCol, msg2)})
			relevant[f2] = true
		}
	}
	pm := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	for f := range relevant {
		for p := range g.Neighbors(f, chickpeas.Outgoing, "HAS_MEMBER") {
			set := pm[p]
			if set == nil {
				set = map[chickpeas.NodeID]bool{}
				pm[p] = set
			}
			set[f] = true
		}
	}
	counts := map[chickpeas.NodeID]map[chickpeas.NodeID]bool{}
	for _, c := range cands {
		if c.p2 == c.p3 {
			continue
		}
		fp2, fp3 := pm[c.p2], pm[c.p3]
		for f1 := range fp2 {
			if f1 == c.f2 || !fp3[f1] {
				continue
			}
			for _, m1 := range m1ByForum[f1] {
				if c.ms2 > m1.ms1+deltaMS && !pm[m1.p1][c.f2] {
					set := counts[m1.p1]
					if set == nil {
						set = map[chickpeas.NodeID]bool{}
						counts[m1.p1] = set
					}
					set[c.msg2] = true
				}
			}
		}
	}
	rows := make([][]any, 0, len(counts))
	for p, ms := range counts {
		rows = append(rows, []any{i64At(idCol, p), int64(len(ms))})
	}
	return sortTruncate(rows, 10, func(a, b []any) bool {
		return cmpChain(
			cmpI64Desc(a[1].(int64), b[1].(int64)),
			cmpI64Asc(a[0].(int64), b[0].(int64)),
		)
	}), nil
}

// finCR1 -- blocked-medium related accounts: <=3-hop reverse transfer
// trace with strictly-decreasing (backward) timestamps; each reached
// account's blocked signIn media emit [otherId, distance, mediumId,
// "Medium"].
func finCR1(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	account, err := finNode(g, "Account", finSeedCR1)
	if err != nil {
		return nil, err
	}
	blockedCol, ok := g.Col("isBlocked")
	if !ok {
		return nil, fmt.Errorf("node column isBlocked missing")
	}
	blocked := blockedCol.Bool()
	return func() ([][]any, error) {
		var rows [][]any
		visited := map[chickpeas.NodeID]bool{account: true}
		type qe struct {
			node   chickpeas.NodeID
			depth  uint32
			lastTS int64
		}
		queue := []qe{{account, 0, math.MaxInt64}}
		var rels []tsRel
		for len(queue) > 0 {
			cur := queue[0]
			queue = queue[1:]
			if cur.depth >= 3 {
				continue
			}
			rels = rels[:0]
			for r := range g.Rels(cur.node, chickpeas.Incoming, "transfer") {
				ts := cols.relTS(r.Pos)
				if ts >= finWS && ts <= finWE && ts < cur.lastTS {
					rels = append(rels, tsRel{ts, r.Neighbor})
				}
			}
			sortTSRels(rels, false)
			if len(rels) > finTruncLimit {
				rels = rels[:finTruncLimit]
			}
			for _, e := range rels {
				if visited[e.nbr] {
					continue
				}
				visited[e.nbr] = true
				dist := cur.depth + 1
				for sig := range g.Rels(e.nbr, chickpeas.Incoming, "signIn") {
					if b, ok := blocked.Get(sig.Neighbor); ok && b {
						rows = append(rows, []any{cols.oid(e.nbr), int64(dist), cols.oid(sig.Neighbor), "Medium"})
					}
				}
				queue = append(queue, qe{e.nbr, dist, e.ts})
			}
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpI64Asc(a[1].(int64), b[1].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
				cmpI64Asc(a[2].(int64), b[2].(int64)),
			)
		}), nil
	}, nil
}

// finCR2 -- fund gathered from loan-applying accounts: reverse-trace
// each owned account (<=3 hops, monotonic backward time), then per
// upstream account sum the loan amounts/balances deposited into it;
// [otherId, sumLoanAmount, sumLoanBalance].
func finCR2(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	person, err := finNode(g, "Person", finSeedOwner)
	if err != nil {
		return nil, err
	}
	loanAmt, ok := g.Col("loanAmount")
	if !ok {
		return nil, fmt.Errorf("node column loanAmount missing")
	}
	loanBal, ok := g.Col("balance")
	if !ok {
		return nil, fmt.Errorf("node column balance missing")
	}
	la, lb := loanAmt.F64(), loanBal.F64()
	return func() ([][]any, error) {
		type sums struct{ amt, bal float64 }
		byAcct := map[chickpeas.NodeID]*sums{}
		var rels []tsRel
		loans := map[chickpeas.NodeID]bool{}
		for own := range g.Rels(person, chickpeas.Outgoing, "own") {
			owned := own.Neighbor
			visited := map[chickpeas.NodeID]bool{owned: true}
			type qe struct {
				node   chickpeas.NodeID
				depth  uint32
				lastTS int64
			}
			queue := []qe{{owned, 0, math.MaxInt64}}
			for len(queue) > 0 {
				cur := queue[0]
				queue = queue[1:]
				if cur.depth >= 3 {
					continue
				}
				rels = rels[:0]
				for r := range g.Rels(cur.node, chickpeas.Incoming, "transfer") {
					rels = append(rels, tsRel{cols.relTS(r.Pos), r.Neighbor})
				}
				sortTSRels(rels, false)
				if len(rels) > finTruncLimit {
					rels = rels[:finTruncLimit]
				}
				for _, e := range rels {
					if e.ts < finWS || e.ts > finWE || e.ts >= cur.lastTS {
						continue
					}
					if !visited[e.nbr] {
						visited[e.nbr] = true
						queue = append(queue, qe{e.nbr, cur.depth + 1, e.ts})
					}
				}
			}
			for acct := range visited {
				if acct == owned {
					continue
				}
				clear(loans)
				var amt, bal float64
				for dep := range g.Rels(acct, chickpeas.Incoming, "deposit") {
					ts := cols.relTS(dep.Pos)
					if ts < finWS || ts > finWE {
						continue
					}
					if !loans[dep.Neighbor] {
						loans[dep.Neighbor] = true
						if v, ok := la.Get(dep.Neighbor); ok {
							amt += v
						}
						if v, ok := lb.Get(dep.Neighbor); ok {
							bal += v
						}
					}
				}
				if len(loans) > 0 {
					e := byAcct[acct]
					if e == nil {
						e = &sums{}
						byAcct[acct] = e
					}
					e.amt += amt
					e.bal += bal
				}
			}
		}
		rows := make([][]any, 0, len(byAcct))
		for acct, s := range byAcct {
			rows = append(rows, []any{cols.oid(acct), s.amt, s.bal})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpF64Desc(a[1].(float64), b[1].(float64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// finCR3 -- shortest in-window transfer path length between the seed
// account and the recorded destination; [[hops]] (-1 unreachable).
func finCR3(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	src, err := finNode(g, "Account", finSeedAccount)
	if err != nil {
		return nil, err
	}
	dst, err := finNode(g, "Account", finSeedDst)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		weight := func(_ chickpeas.NodeID, r chickpeas.RelRef) float64 {
			ts := cols.relTS(r.Pos)
			if ts >= finWS && ts <= finWE {
				return 1.0
			}
			return inf
		}
		if cost, ok := g.WeightedShortestPath(src, dst, chickpeas.Outgoing, g.Match("transfer"), weight); ok && finite(cost) {
			return [][]any{{int64(cost)}}, nil
		}
		return [][]any{{int64(-1)}}, nil
	}, nil
}

// finCR4 -- time-ordered transfer cycles back to the seed (amounts >=
// 1000, cycle within the 90-day window, <=6 nodes, capped at 1000
// cycles); one row per cycle's id sequence.
func finCR4(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	account, err := finNode(g, "Account", finSeedCycle)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		const maxCycleLen, maxCycles = 6, 1000
		const minAmount = 1000.0
		var cycles [][]chickpeas.NodeID
		path := []chickpeas.NodeID{account}
		onPath := map[chickpeas.NodeID]bool{account: true}
		var dfs func(node chickpeas.NodeID, lastTS int64, firstTS int64, haveFirst bool)
		dfs = func(node chickpeas.NodeID, lastTS int64, firstTS int64, haveFirst bool) {
			if len(path) > maxCycleLen || len(cycles) >= maxCycles {
				return
			}
			for r := range g.Rels(node, chickpeas.Outgoing, "transfer") {
				ts := cols.relTS(r.Pos)
				if ts <= lastTS || cols.relAmt(r.Pos) < minAmount {
					continue
				}
				f0 := ts
				if haveFirst {
					f0 = firstTS
				}
				if ts-f0 > finWindowMS {
					continue
				}
				if r.Neighbor == account {
					if len(path) >= 2 {
						cycles = append(cycles, append([]chickpeas.NodeID(nil), path...))
					}
					continue
				}
				if onPath[r.Neighbor] {
					continue
				}
				path = append(path, r.Neighbor)
				onPath[r.Neighbor] = true
				dfs(r.Neighbor, ts, f0, true)
				path = path[:len(path)-1]
				delete(onPath, r.Neighbor)
			}
		}
		dfs(account, math.MinInt64, 0, false)
		rows := make([][]any, len(cycles))
		for i, cy := range cycles {
			row := make([]any, len(cy))
			for j, n := range cy {
				row[j] = cols.oid(n)
			}
			rows[i] = row
		}
		return rows, nil
	}, nil
}

// finCR5 -- exact downstream transfer traces from the owner's accounts
// (<=3 hops, strictly increasing timestamps, acyclic); each trace is
// one single-list-cell row (the manifest's unwrap1 norm flattens it,
// matching the GQL twin's list projection).
func finCR5(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	person, err := finNode(g, "Person", finSeedOwner)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		var all [][]chickpeas.NodeID
		var dfs func(node chickpeas.NodeID, lastTS int64, path *[]chickpeas.NodeID, visited map[chickpeas.NodeID]bool, depth int)
		dfs = func(node chickpeas.NodeID, lastTS int64, path *[]chickpeas.NodeID, visited map[chickpeas.NodeID]bool, depth int) {
			if depth >= 3 {
				return
			}
			byNeighbor := map[chickpeas.NodeID]int64{}
			for r := range g.Rels(node, chickpeas.Outgoing, "transfer") {
				ts := cols.relTS(r.Pos)
				if ts >= finWS && ts <= finWE && ts > lastTS && !visited[r.Neighbor] {
					if cur, ok := byNeighbor[r.Neighbor]; !ok || ts < cur {
						byNeighbor[r.Neighbor] = ts
					}
				}
			}
			cands := make([]tsRel, 0, len(byNeighbor))
			for n, ts := range byNeighbor {
				cands = append(cands, tsRel{ts, n})
			}
			if len(cands) > finTruncLimit {
				sortTSRels(cands, false)
				cands = cands[:finTruncLimit]
			}
			for _, c := range cands {
				*path = append(*path, c.nbr)
				visited[c.nbr] = true
				all = append(all, append([]chickpeas.NodeID(nil), *path...))
				dfs(c.nbr, c.ts, path, visited, depth+1)
				*path = (*path)[:len(*path)-1]
				delete(visited, c.nbr)
			}
		}
		for r := range g.Rels(person, chickpeas.Outgoing, "own") {
			start := r.Neighbor
			path := []chickpeas.NodeID{start}
			visited := map[chickpeas.NodeID]bool{start: true}
			dfs(start, math.MinInt64, &path, visited, 0)
		}
		// Dedup node sequences (parallel rels collapse to one path).
		sort.Slice(all, func(i, j int) bool {
			a, b := all[i], all[j]
			for k := 0; k < len(a) && k < len(b); k++ {
				if a[k] != b[k] {
					return a[k] < b[k]
				}
			}
			return len(a) < len(b)
		})
		var rows [][]any
		for i, p := range all {
			if i > 0 && slicesEqualNodes(all[i-1], p) {
				continue
			}
			ids := make([]any, len(p))
			for j, n := range p {
				ids[j] = cols.oid(n)
			}
			rows = append(rows, []any{ids})
		}
		return rows, nil
	}, nil
}

// finCR6 -- withdrawal after many-to-one transfer (single-hop
// cross-engine reduction): the card's in-window withdrawals bound a
// fan-in of incoming transfers, summed per source; [srcId,
// sumRel1Amount, sumRel2Amount].
func finCR6(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	card, err := finNode(g, "Account", finSeedCard)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		const threshold1, threshold2 = 0.0, 0.0
		var totalWithdraw float64
		lastWithdraw := int64(math.MinInt64)
		haveWithdraw := false
		for r := range g.Rels(card, chickpeas.Outgoing, "withdraw") {
			ts := cols.relTS(r.Pos)
			amt := cols.relAmt(r.Pos)
			if ts >= finWS && ts <= finWE && amt > threshold2 {
				totalWithdraw += amt
				if ts > lastWithdraw {
					lastWithdraw = ts
				}
				haveWithdraw = true
			}
		}
		if !haveWithdraw {
			return [][]any{}, nil
		}
		type inRel struct {
			ts  int64
			amt float64
			src chickpeas.NodeID
		}
		var inRels []inRel
		for r := range g.Rels(card, chickpeas.Incoming, "transfer") {
			ts := cols.relTS(r.Pos)
			amt := cols.relAmt(r.Pos)
			if ts >= finWS && ts <= finWE && amt > threshold1 && ts <= lastWithdraw {
				inRels = append(inRels, inRel{ts, amt, r.Neighbor})
			}
		}
		if len(inRels) > finTruncLimit {
			sort.Slice(inRels, func(i, j int) bool { return inRels[i].ts > inRels[j].ts })
			inRels = inRels[:finTruncLimit]
		}
		bySrc := map[chickpeas.NodeID]float64{}
		for _, r := range inRels {
			bySrc[r.src] += r.amt
		}
		rows := make([][]any, 0, len(bySrc))
		for s, a := range bySrc {
			rows = append(rows, []any{cols.oid(s), a, totalWithdraw})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpF64Desc(a[1].(float64), b[1].(float64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// finCR7 -- transfer in/out ratio around the seed account;
// [[numSrc, numDst, inOutRatio]] (ratio rounded 3dp, -1 when no
// outgoing amount).
func finCR7(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	account, err := finNode(g, "Account", finSeedAccount)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		const threshold = 0.0
		gather := func(dir chickpeas.Direction) (int64, float64) {
			var rels []tsAmtRel
			for r := range g.Rels(account, dir, "transfer") {
				ts := cols.relTS(r.Pos)
				amt := cols.relAmt(r.Pos)
				if ts >= finWS && ts <= finWE && amt > threshold {
					rels = append(rels, tsAmtRel{ts, amt, r.Neighbor})
				}
			}
			rels = truncByTS(rels, finTruncLimit, false)
			distinct := map[chickpeas.NodeID]bool{}
			var sum float64
			for _, r := range rels {
				distinct[r.nbr] = true
				sum += r.amt
			}
			return int64(len(distinct)), sum
		}
		numSrc, inAmt := gather(chickpeas.Incoming)
		numDst, outAmt := gather(chickpeas.Outgoing)
		ratio := -1.0
		if outAmt > 0 {
			ratio = round3f(inAmt / outAmt)
		}
		return [][]any{{numSrc, numDst, ratio}}, nil
	}, nil
}

// finCR8 -- transfer trace after loan applied: BFS from the loan's
// deposited accounts over transfer/withdraw (<=3 from the loan), each
// hop's amount gated by the node's upstream inflow; [dstId, ratio,
// minDistance] (ratio = inflow / loanAmount, rounded 3dp).
func finCR8(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	loan, err := finNode(g, "Loan", finSeedLoan)
	if err != nil {
		return nil, err
	}
	laCol, ok := g.Col("loanAmount")
	if !ok {
		return nil, fmt.Errorf("node column loanAmount missing")
	}
	la := laCol.F64()
	return func() ([][]any, error) {
		const threshold = 0.0
		loanAmount, ok := la.Get(loan)
		if !ok {
			loanAmount = 1.0
		}
		type depRel struct {
			acct chickpeas.NodeID
			amt  float64
		}
		var deposits []depRel
		for r := range g.Rels(loan, chickpeas.Outgoing, "deposit") {
			ts := cols.relTS(r.Pos)
			if ts >= finWS && ts <= finWE {
				deposits = append(deposits, depRel{r.Neighbor, cols.relAmt(r.Pos)})
			}
		}
		type acc struct {
			inflow float64
			dist   uint32
		}
		results := map[chickpeas.NodeID]*acc{}
		type amtRel struct {
			amt float64
			nbr chickpeas.NodeID
		}
		var rels []amtRel
		for _, dep := range deposits {
			visited := map[chickpeas.NodeID]bool{dep.acct: true}
			type qe struct {
				node   chickpeas.NodeID
				dist   uint32
				inflow float64
			}
			queue := []qe{{dep.acct, 1, dep.amt}}
			for len(queue) > 0 {
				cur := queue[0]
				queue = queue[1:]
				e := results[cur.node]
				if e == nil {
					results[cur.node] = &acc{cur.inflow, cur.dist}
				} else {
					e.inflow += cur.inflow
					if cur.dist < e.dist {
						e.dist = cur.dist
					}
				}
				if cur.dist >= 3 {
					continue
				}
				var upstream float64
				for r := range g.Rels(cur.node, chickpeas.Incoming, "transfer") {
					ts := cols.relTS(r.Pos)
					if ts >= finWS && ts <= finWE {
						upstream += cols.relAmt(r.Pos)
					}
				}
				rels = rels[:0]
				for _, relType := range []string{"transfer", "withdraw"} {
					for r := range g.Rels(cur.node, chickpeas.Outgoing, relType) {
						ts := cols.relTS(r.Pos)
						if ts >= finWS && ts <= finWE {
							rels = append(rels, amtRel{cols.relAmt(r.Pos), r.Neighbor})
						}
					}
				}
				// The Rust reference compares its truncation order
				// case-SENSITIVELY ("DESC"), so the harness's "desc"
				// falls through to the ascending sort -- the lowest
				// amount claims each node. The refs pin that behavior.
				sort.Slice(rels, func(i, j int) bool { return rels[i].amt < rels[j].amt })
				if len(rels) > finTruncLimit {
					rels = rels[:finTruncLimit]
				}
				for _, r := range rels {
					if r.amt > threshold*upstream && !visited[r.nbr] {
						visited[r.nbr] = true
						queue = append(queue, qe{r.nbr, cur.dist + 1, r.amt})
					}
				}
			}
		}
		rows := make([][]any, 0, len(results))
		for did, a := range results {
			rows = append(rows, []any{cols.oid(did), round3f(a.inflow / loanAmount), int64(a.dist)})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[2].(int64), b[2].(int64)),
				cmpF64Desc(a[1].(float64), b[1].(float64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// finCR9 -- money laundering ratios around the seed account;
// [[ratioRepay, ratioDeposit, ratioTransfer]] (each rounded 3dp, -1 on
// an empty denominator).
func finCR9(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	account, err := finNode(g, "Account", finSeedAccount)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		const threshold = 0.0
		gather := func(dir chickpeas.Direction, relType string, amtFloor bool) []tsAmtRel {
			var rels []tsAmtRel
			for r := range g.Rels(account, dir, relType) {
				ts := cols.relTS(r.Pos)
				amt := cols.relAmt(r.Pos)
				if ts < finWS || ts > finWE {
					continue
				}
				if amtFloor && amt < threshold {
					continue
				}
				rels = append(rels, tsAmtRel{ts, amt, r.Neighbor})
			}
			return truncByTS(rels, finTruncLimit, false)
		}
		sum := func(rels []tsAmtRel) float64 {
			var s float64
			for _, r := range rels {
				s += r.amt
			}
			return s
		}
		rel1 := sum(gather(chickpeas.Outgoing, "repay", false))
		rel2 := sum(gather(chickpeas.Incoming, "deposit", false))
		rel3 := sum(gather(chickpeas.Outgoing, "transfer", true))
		rel4 := sum(gather(chickpeas.Incoming, "transfer", true))
		ratio := func(num, den float64) float64 {
			if den == 0 {
				return -1.0
			}
			return round3f(num / den)
		}
		return [][]any{{ratio(rel1, rel2), ratio(rel1, rel4), ratio(rel3, rel4)}}, nil
	}, nil
}

// finCR10 -- investor similarity: co-investors per company the seed
// invests in (window is full, so all invest rels qualify); [otherId,
// sharedCompanyCount].
func finCR10(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	person, err := finNode(g, "Person", finSeedInvestor)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		companies := map[chickpeas.NodeID]bool{}
		for r := range g.Rels(person, chickpeas.Outgoing, "invest") {
			ts := cols.relTS(r.Pos)
			if ts >= finWS && ts <= finWE {
				companies[r.Neighbor] = true
			}
		}
		shared := map[chickpeas.NodeID]int64{}
		for c := range companies {
			for r := range g.Rels(c, chickpeas.Incoming, "invest") {
				if r.Neighbor != person {
					shared[r.Neighbor]++
				}
			}
		}
		rows := make([][]any, 0, len(shared))
		for o, c := range shared {
			rows = append(rows, []any{cols.oid(o), c})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[1].(int64), b[1].(int64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

// finCR11 -- guarantee exposure: walk the guarantee chain from the
// seed person, summing every reached person's applied loan amounts;
// [[total]].
func finCR11(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	person, err := finNode(g, "Person", finSeedPerson)
	if err != nil {
		return nil, err
	}
	laCol, ok := g.RelCol("loanAmount")
	if !ok {
		return nil, fmt.Errorf("rel column loanAmount missing")
	}
	la := laCol.F64()
	return func() ([][]any, error) {
		visited := map[chickpeas.NodeID]bool{person: true}
		queue := []chickpeas.NodeID{person}
		var total float64
		for len(queue) > 0 {
			p := queue[0]
			queue = queue[1:]
			for r := range g.Rels(p, chickpeas.Outgoing, "apply") {
				if v, ok := la.Get(r.Pos); ok {
					total += v
				}
			}
			for r := range g.Rels(p, chickpeas.Outgoing, "guarantee") {
				if !visited[r.Neighbor] {
					visited[r.Neighbor] = true
					queue = append(queue, r.Neighbor)
				}
			}
		}
		return [][]any{{total}}, nil
	}, nil
}

// finCR12 -- transfer-to-company statistics: the owner's accounts'
// in-window transfers into company-owned accounts, summed per target;
// [compAccountId, summedAmount].
func finCR12(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cols, err := finColsOf(g)
	if err != nil {
		return nil, err
	}
	person, err := finNode(g, "Person", finSeedOwner)
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		companies, ok := g.NodesWithLabel("Company")
		if !ok {
			return [][]any{}, nil
		}
		var personAccounts []chickpeas.NodeID
		for r := range g.Rels(person, chickpeas.Outgoing, "own") {
			personAccounts = append(personAccounts, r.Neighbor)
		}
		if len(personAccounts) > finTruncLimit {
			slices.Sort(personAccounts)
			personAccounts = personAccounts[:finTruncLimit]
		}
		amounts := map[chickpeas.NodeID]float64{}
		var transfers []tsAmtRel
		for _, acct := range personAccounts {
			transfers = transfers[:0]
			for r := range g.Rels(acct, chickpeas.Outgoing, "transfer") {
				ts := cols.relTS(r.Pos)
				if ts >= finWS && ts <= finWE {
					transfers = append(transfers, tsAmtRel{ts, cols.relAmt(r.Pos), r.Neighbor})
				}
			}
			if len(transfers) > finTruncLimit {
				sort.Slice(transfers, func(i, j int) bool { return transfers[i].amt > transfers[j].amt })
				transfers = transfers[:finTruncLimit]
			}
			for _, t := range transfers {
				companyOwned := false
				for own := range g.Rels(t.nbr, chickpeas.Incoming, "own") {
					if companies.Contains(own.Neighbor) {
						companyOwned = true
						break
					}
				}
				if companyOwned {
					amounts[t.nbr] += t.amt
				}
			}
		}
		rows := make([][]any, 0, len(amounts))
		for a, s := range amounts {
			rows = append(rows, []any{cols.oid(a), s})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpF64Desc(a[1].(float64), b[1].(float64)),
				cmpI64Asc(a[0].(int64), b[0].(int64)),
			)
		}), nil
	}, nil
}

