// icIS6 -- the forum and moderator of the seed post; [[forumId,
// moderatorId]].
func icIS6(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	post, err := icSeedPost(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	var roots chickpeas.RootsVia
	if rt, ok := g.RelType("REPLY_OF"); ok {
		roots = g.RootsVia(rt, chickpeas.Outgoing)
	}
	return func() ([][]any, error) {
		root := post
		if roots != nil {
			root = roots[post]
		}
		forum, ok := g.FirstNeighbor(root, chickpeas.Incoming, "CONTAINER_OF")
		if !ok {
			return [][]any{}, nil
		}
		moderator, ok := g.FirstNeighbor(forum, chickpeas.Outgoing, "HAS_MODERATOR")
		if !ok {
			return [][]any{}, nil
		}
		return [][]any{{i64At(idCol, forum), i64At(idCol, moderator)}}, nil
	}, nil
}

// icIS7 -- direct replies to the seed post; [replyMs, authorId, knows]
// (ms desc, author id asc); knows = author is a friend of the post's
// author (0/1).
func icIS7(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	post, err := icSeedPost(g)
	if err != nil {
		return nil, err
	}
	idCol, err := nodeI64Col(g, "id")
	if err != nil {
		return nil, err
	}
	msCol, err := nodeI64Col(g, "ms")
	if err != nil {
		return nil, err
	}
	return func() ([][]any, error) {
		author, hasAuthor := creatorOf(g, post)
		authorFriends := map[chickpeas.NodeID]bool{}
		if hasAuthor {
			for f := range g.Neighbors(author, chickpeas.Both, "KNOWS") {
				authorFriends[f] = true
			}
		}
		var rows [][]any
		for reply := range g.Neighbors(post, chickpeas.Incoming, "REPLY_OF") {
			ra, ok := creatorOf(g, reply)
			knows := int64(0)
			raID := int64(0)
			if ok {
				raID = i64At(idCol, ra)
				if hasAuthor && ra != author && authorFriends[ra] {
					knows = 1
				}
			}
			rows = append(rows, []any{i64At(msCol, reply), raID, knows})
		}
		return sortTruncate(rows, 0, func(a, b []any) bool {
			return cmpChain(
				cmpI64Desc(a[0].(int64), b[0].(int64)),
				cmpI64Asc(a[1].(int64), b[1].(int64)),
			)
		}), nil
	}, nil
}

// spbQ1 (basic q1): creative works about|mentions the topic, ranked by
// dateModified descending.
func spbQ1(g *chickpeas.Snapshot) ([][]any, error) {
	return spbURIRows(g, spbQ1Rank(g)), nil
}

// spbQ2 (basic q2): describe one concrete creative work -- the
// CreativeWork with the derived uri, only if it carries the required
// title. The parameter derivation is untimed prepare; the timed run is
// the lookup itself.
func spbQ2(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cwURI := spbQ2CW(g)
	return func() ([][]any, error) {
		set, ok := g.NodesWithProperty("CreativeWork", "uri", cwURI)
		if !ok {
			return [][]any{}, nil
		}
		for n := range set.Iter() {
			if _, hasTitle := g.Prop(n, "title").Str(); hasTitle {
				return [][]any{{spbURIOf(g, n)}}, nil
			}
			break // first (lowest-id) member only, like the Rust iter().next()
		}
		return [][]any{}, nil
	}, nil
}

// spbQ3 (basic q3): works tagging the topic with a dateCreated, newest
// first.
func spbQ3(g *chickpeas.Snapshot) ([][]any, error) {
	rows := spbTaggingWorks(g, spbTopic, "CreativeWork", "dateCreated")
	return spbURIRows(g, spbRankDated(rows, spbAll)), nil
}

// spbQ4 (basic q4): blog posts tagging the topic with a dateCreated,
// newest first.
func spbQ4(g *chickpeas.Snapshot) ([][]any, error) {
