	return spbURIRows(g, spbRankDated(rows, spbAll)), nil
}

// spbQ5 (basic q5): per labelled topic, how many works of the type /
// audience tag it inside the exclusive dateModified window; count
// descending, label ascending.
func spbQ5(g *chickpeas.Snapshot) ([][]any, error) {
	works, ok := g.NodesWithLabel(spbCWType)
	if !ok {
		return [][]any{}, nil
	}
	startMs, endMs := spbParseMs(spbDateFrom), spbParseMs(spbDateTo)
	counts := map[chickpeas.NodeID]int64{}
	for cw := range works.Iter() {
		if !spbHasNeighborWithURI(g, cw, "audience", spbAudience) {
			continue
		}
		dt, ok := g.Prop(cw, "dateModified").Str()
		if !ok {
			continue
		}
		if ms := spbParseMs(dt); !(ms > startMs && ms < endMs) {
			continue
		}
		topics := map[chickpeas.NodeID]bool{}
		for _, pred := range spbTagPreds {
			for t := range g.Neighbors(cw, chickpeas.Outgoing, pred) {
				topics[t] = true
			}
		}
		for t := range topics {
			if _, hasLabel := g.Prop(t, "label").Str(); hasLabel {
				counts[t]++
			}
		}
	}
	rows := make([][]any, 0, len(counts))
	for t, n := range counts {
		label, _ := g.Prop(t, "label").Str()
		rows = append(rows, []any{label, n})
	}
	spbSortKV(rows)
	return rows, nil
}

// spbQ7 (basic q7): date-range retrieval with facets -- works of the
// type created inside [from, to] carrying title and liveCoverage, with
// category/audience rels pinned to the parameter uris.
func spbQ7(g *chickpeas.Snapshot) ([][]any, error) {
	works, ok := g.NodesWithLabel(spbCWType)
	if !ok {
		return [][]any{}, nil
	}
	var out []chickpeas.NodeID
	for w := range works.Iter() {
		created, ok := g.Prop(w, "dateCreated").Str()
		if !ok || created < spbDateFrom || created > spbDateTo {
			continue
		}
		if _, hasTitle := g.Prop(w, "title").Str(); !hasTitle {
			continue
		}
		if _, hasLive := g.Prop(w, "liveCoverage").Value(); !hasLive {
			continue
		}
		if !spbHasNeighborWithURI(g, w, "category", spbCategory) ||
			!spbHasNeighborWithURI(g, w, "audience", spbAudience) {
			continue
		}
		out = append(out, w)
	}
	slices.Sort(out)
	return spbURIRows(g, out), nil
}

// spbQ9 (basic q9): works related to the derived creative work by
// shared tagged entities, scored 2*(about,about) + 1.5*(about,mentions)
// + 1*(mentions,about) + 0.5*(mentions,mentions); the emitted score is
// doubled to an integer, matching the stored ref (which sidesteps
// decimal-coefficient quirks on the SPARQL side).
func spbQ9(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cwURI := spbQ2CW(g)
	return func() ([][]any, error) {
		focal, ok := spbNodeByURI(g, cwURI)
		if !ok {
			return [][]any{}, nil
		}
		focalAbout := map[chickpeas.NodeID]bool{}
		for e := range g.Neighbors(focal, chickpeas.Outgoing, "about") {
			focalAbout[e] = true
		}
		focalMentions := map[chickpeas.NodeID]bool{}
		for e := range g.Neighbors(focal, chickpeas.Outgoing, "mentions") {
			focalMentions[e] = true
		}

		candidates := map[chickpeas.NodeID]bool{}
		collect := func(ents map[chickpeas.NodeID]bool) {
			for ent := range ents {
				for _, rel := range spbTagPreds {
					for w := range g.Neighbors(ent, chickpeas.Incoming, rel) {
						if w != focal && g.HasLabel(w, "CreativeWork") {
							candidates[w] = true
						}
					}
				}
			}
		}
		collect(focalAbout)
		collect(focalMentions)

		var rows [][]any
		for o := range candidates {
			if _, hasDT := g.Prop(o, "dateModified").Str(); !hasDT {
				continue
			}
			var a2a, a2m, m2a, m2m int64
			for e := range g.Neighbors(o, chickpeas.Outgoing, "about") {
				if focalAbout[e] {
					a2a++
				}
				if focalMentions[e] {
					m2a++
				}
			}
			for e := range g.Neighbors(o, chickpeas.Outgoing, "mentions") {
				if focalAbout[e] {
					a2m++
				}
				if focalMentions[e] {
					m2m++
				}
			}
			// score*2 stays integral: 4*a2a + 3*a2m + 2*m2a + m2m.
			score2 := 4*a2a + 3*a2m + 2*m2a + m2m
			if score2 <= 0 {
				continue
			}
			rows = append(rows, []any{spbURIOf(g, o), score2})
		}
		sort.Slice(rows, func(i, j int) bool {
			a, b := rows[i][1].(int64), rows[j][1].(int64)
			if a != b {
				return a > b
			}
			return rows[i][0].(string) < rows[j][0].(string)
		})
		return rows, nil
	}, nil
}

// spbA1 (advanced q1): creative works with an `about` rel to the topic
// and a dateModified, newest first.
func spbA1(g *chickpeas.Snapshot) ([][]any, error) {
	topic, ok := spbNodeByURI(g, spbTopic)
	if !ok {
		return [][]any{}, nil
	}
	cworks, ok := g.NodesWithLabel("CreativeWork")
	if !ok {
		return [][]any{}, nil
	}
	var rows []spbDated
	for w := range g.Neighbors(topic, chickpeas.Incoming, "about") {
		if !cworks.Contains(w) {
			continue
		}
		if dt, ok := g.Prop(w, "dateModified").Str(); ok {
			rows = append(rows, spbDated{w, dt})
		}
	}
	return spbURIRows(g, spbRankDated(rows, spbAll)), nil
}

// spbA2 (advanced q2): the derived creative work's CreativeWork subtype
// labels, sorted; empty for a missing or titleless work. The parameter
// derivation is untimed prepare.
func spbA2(g *chickpeas.Snapshot) (func() ([][]any, error), error) {
	cwURI := spbQ2CW(g)
	return func() ([][]any, error) {
		work, ok := spbNodeByURI(g, cwURI)
		if !ok || !g.HasLabel(work, "CreativeWork") {
			return [][]any{}, nil
		}
		if _, hasTitle := g.Prop(work, "title").Str(); !hasTitle {
			return [][]any{}, nil
		}
		var rows [][]any
		for _, label := range spbSubtypes {
			if g.HasLabel(work, label) {
				rows = append(rows, []any{label})
			}
		}
		return rows, nil
	}, nil
}

// spbA3 (advanced q3): in-window works counted by the minute-of-hour of
// dateModified (the SPARQL MINUTES), minute emitted as a bare decimal
// string.
func spbA3(g *chickpeas.Snapshot) ([][]any, error) {
	works, ok := g.NodesWithLabel("CreativeWork")
	if !ok {
		return [][]any{}, nil
	}
	counts := map[int64]int64{}
	for w := range works.Iter() {
		dt, ok := g.Prop(w, "dateModified").Str()
		if !ok || !(dt > spbDateFrom && dt < spbDateTo) {
			continue
		}
		if len(dt) < 16 {
			continue
		}
		minute, ok := spbAtoi(dt[14:16])
		if !ok {
			continue
		}
		counts[minute]++
	}
	rows := make([][]any, 0, len(counts))
	for m, c := range counts {
		rows = append(rows, []any{strconvItoa(m), c})
	}
	spbSortKV(rows)
	return rows, nil
}

// spbA4 (advanced q4): works per concrete subtype with dateModified in
// the window, count descending.
func spbA4(g *chickpeas.Snapshot) ([][]any, error) {
	var rows [][]any
	for _, label := range spbSubtypes {
		set, ok := g.NodesWithLabel(label)
		if !ok {
			continue
		}
		var n int64
		for w := range set.Iter() {
			if dm, ok := g.Prop(w, "dateModified").Str(); ok && dm > spbDateFrom && dm < spbDateTo {
				n++
			}
		}
		if n > 0 {
			rows = append(rows, []any{label, n})
		}
	}
	spbSortKV(rows)
	return rows, nil
}

// spbA5 (advanced q5): about-targets of the entity type ranked by how
// many works category-linked to either pinned category are about them
// (per about rel, duplicates included).
func spbA5(g *chickpeas.Snapshot) ([][]any, error) {
	entities, ok := g.NodesWithLabel(spbEntityLabel)
	if !ok {
		return [][]any{}, nil
	}
	works, ok := g.NodesWithLabel("CreativeWork")
	if !ok {
		return [][]any{}, nil
	}
	counts := map[chickpeas.NodeID]int64{}
	for w := range works.Iter() {
		inCategory := false
		for c := range g.Neighbors(w, chickpeas.Outgoing, "category") {
			if u, ok := g.Prop(c, "uri").Str(); ok && (u == spbCatCompany || u == spbCategory) {
				inCategory = true
				break
			}
		}
		if !inCategory {
			continue
		}
		for about := range g.Neighbors(w, chickpeas.Outgoing, "about") {
			if entities.Contains(about) {
				counts[about]++
			}
		}
	}
	return spbCountRows(g, counts), nil
}

// spbA6 (advanced q6): about-entity types (leaf classes plus the
// forward-chained Thing) ranked by covered (work, about) pairs, over
// works with the live flag and audience.
func spbA6(g *chickpeas.Snapshot) ([][]any, error) {
	works, ok := g.NodesWithLabel("CreativeWork")
	if !ok {
		return [][]any{}, nil
	}
	entityTypes := []string{"Company", "Event", "Thing"}
	type typeSet struct {
		name string
		set  *nodeset.Set
	}
	var sets []typeSet
	for _, ty := range entityTypes {
		if s, ok := g.NodesWithLabel(ty); ok {
			sets = append(sets, typeSet{ty, s})
		}
	}
	counts := map[string]int64{}
	for w := range works.Iter() {
		if live, ok := g.Prop(w, "liveCoverage").Bool(); !ok || !live {
			continue
		}
		if !spbHasNeighborWithURI(g, w, "audience", spbAudience) {
			continue
		}
		for about := range g.Neighbors(w, chickpeas.Outgoing, "about") {
			for _, ts := range sets {
				if ts.set.Contains(about) {
					counts[ts.name]++
				}
			}
		}
	}
	rows := make([][]any, 0, len(counts))
	for ty, n := range counts {
		rows = append(rows, []any{ty, n})
	}
	spbSortKV(rows)
	return rows, nil
}

