		}
		aboutThing := false
		for a := range g.Neighbors(w, chickpeas.Outgoing, "about") {
			if g.HasLabel(a, spbEntityLabel) {
				aboutThing = true
				break
			}
		}
		if !aboutThing {
			continue
		}
		mentionsThing := false
		for m := range g.Neighbors(w, chickpeas.Outgoing, "mentions") {
			if g.HasLabel(m, spbEntityLabel) {
				mentionsThing = true
				break
			}
		}
