// spbA23 (advanced q23, final drill-down): per about/mentions topic of
// the title-matching, category-pinned works with the BGP bound, the
// count of distinct dateCreated calendar days; [uri, days] count
// descending then uri.
func spbA23(g *chickpeas.Snapshot) ([][]any, error) {
	byTag := map[chickpeas.NodeID]map[int64]bool{}
	for w := range g.FullTextSearch("CreativeWork", "title", spbWord).Iter() {
		if !spbHasNeighborWithURI(g, w, "category", spbCategory) {
			continue
		}
		created, ok := g.Prop(w, "dateCreated").Str()
		if !ok {
			continue
		}
		if _, ok := g.Prop(w, "description").Str(); !ok {
			continue
		}
		if !spbHasRel(g, w, "audience") || !spbHasRel(g, w, "primaryFormat") {
			continue
		}
		if _, ok := g.Prop(w, "liveCoverage").Value(); !ok {
			continue
		}
		if len(created) < 10 {
			continue
		}
		y, okY := spbAtoi(created[0:4])
		m, okM := spbAtoi(created[5:7])
		d, okD := spbAtoi(created[8:10])
		if !okY || !okM || !okD {
			continue
		}
		day := dayFromCivil(y, m, d)
		for _, pred := range spbTagPreds {
			for t := range g.Neighbors(w, chickpeas.Outgoing, pred) {
				set := byTag[t]
				if set == nil {
					set = map[int64]bool{}
					byTag[t] = set
				}
				set[day] = true
			}
		}
	}
	rows := make([][]any, 0, len(byTag))
	for t, days := range byTag {
		rows = append(rows, []any{spbURIOf(g, t), int64(len(days))})
	}
	spbSortKV(rows)
	return rows, nil
}

// spbA24 (advanced q24, relatedness time-line): per calendar day, the
// count of works about BOTH entities, ["YYYY-MM-DD", count] ascending.
func spbA24(g *chickpeas.Snapshot) ([][]any, error) {
	a, okA := spbNodeByURI(g, spbTopic)
	b, okB := spbNodeByURI(g, spbEntB)
	if !okA || !okB {
		return [][]any{}, nil
	}
	aboutA := map[chickpeas.NodeID]bool{}
	for w := range g.Neighbors(a, chickpeas.Incoming, "about") {
		aboutA[w] = true
	}
	both := map[chickpeas.NodeID]bool{}
	for w := range g.Neighbors(b, chickpeas.Incoming, "about") {
		if aboutA[w] && g.HasLabel(w, "CreativeWork") {
			both[w] = true
		}
	}
	perDay := map[string]int64{}
	for w := range both {
		created, ok := g.Prop(w, "dateCreated").Str()
		if !ok || len(created) < 10 {
			continue
		}
		y, okY := spbAtoi(created[0:4])
		m, okM := spbAtoi(created[5:7])
		d, okD := spbAtoi(created[8:10])
		if !okY || !okM || !okD {
			continue
		}
		perDay[fmt.Sprintf("%04d-%02d-%02d", y, m, d)]++
	}
	rows := make([][]any, 0, len(perDay))
	for day, n := range perDay {
		rows = append(rows, []any{day, n})
	}
	sort.Slice(rows, func(i, j int) bool { return rows[i][0].(string) < rows[j][0].(string) })
	return rows, nil
}

// spbA25 (advanced q25, related entities): entities co-occurring with
// the topic in works' about links, counted by distinct dateCreated
// days; [who-uri, days] ordered days descending then node id.
func spbA25(g *chickpeas.Snapshot) ([][]any, error) {
	a, ok := spbNodeByURI(g, spbTopic)
	if !ok {
		return [][]any{}, nil
	}
	days := map[chickpeas.NodeID]map[string]bool{}
	for cw := range g.Neighbors(a, chickpeas.Incoming, "about") {
		if !g.HasLabel(cw, "CreativeWork") {
			continue
		}
		created, ok := g.Prop(cw, "dateCreated").Str()
		if !ok || len(created) < 10 {
			continue
		}
		day := created[:10]
		for who := range g.Neighbors(cw, chickpeas.Outgoing, "about") {
			if who == a {
				continue
			}
			set := days[who]
			if set == nil {
				set = map[string]bool{}
				days[who] = set
			}
			set[day] = true
		}
	}
	type row struct {
		who chickpeas.NodeID
		n   int64
	}
	rows := make([]row, 0, len(days))
	for who, set := range days {
		rows = append(rows, row{who, int64(len(set))})
	}
	sort.Slice(rows, func(i, j int) bool {
		if rows[i].n != rows[j].n {
			return rows[i].n > rows[j].n
		}
		return rows[i].who < rows[j].who
	})
	out := make([][]any, len(rows))
	for i, r := range rows {
		out[i] = []any{spbURIOf(g, r.who), r.n}
	}
	return out, nil
}

// GABFS is breadth-first depth from source over forward rels;
// unreachable nodes get MaxInt64, per the spec.
func GABFS(g *chickpeas.Snapshot, source uint32, directed bool) []int64 {
	n := g.NodeCount()
	dir := gaFwd(directed)
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	if source >= n {
		return dist
	}
	dist[source] = 0
	queue := make([]uint32, 0, n)
	queue = append(queue, source)
	for head := 0; head < len(queue); head++ {
		u := queue[head]
		du := dist[u]
		for w := range g.Neighbors(u, dir) {
			if dist[w] == math.MaxInt64 {
				dist[w] = du + 1
				queue = append(queue, w)
			}
		}
	}
	return dist
}

// GAPageRank runs `iterations` synchronous updates with the given
// damping; sinks redistribute their rank uniformly. Pull formulation:
// each node sums its in-neighbours' shares into a disjoint slot.
func GAPageRank(g *chickpeas.Snapshot, directed bool, damping float64, iterations int) []float64 {
	n := int(g.NodeCount())
	if n == 0 {
		return nil
	}
	nf := float64(n)
	out := gaFwd(directed)
	inDir := chickpeas.Incoming
	if !directed {
		inDir = chickpeas.Both
	}
	outdeg := make([]uint32, n)
	parallel.For(n, func(lo, hi int) {
		for v := lo; v < hi; v++ {
			var d uint32
			for range g.Neighbors(uint32(v), out) {
				d++
			}
			outdeg[v] = d
		}
	})
	pr := make([]float64, n)
	for i := range pr {
		pr[i] = 1.0 / nf
	}
	next := make([]float64, n)
	for range iterations {
		var dangling float64
		for v := range n {
			if outdeg[v] == 0 {
				dangling += pr[v]
			}
		}
		base := (1.0-damping)/nf + damping*dangling/nf
		parallel.For(n, func(lo, hi int) {
			for v := lo; v < hi; v++ {
				var pull float64
				for u := range g.Neighbors(uint32(v), inDir) {
					if d := outdeg[u]; d > 0 {
						pull += pr[u] / float64(d)
					}
				}
				next[v] = base + damping*pull
			}
		})
		pr, next = next, pr
	}
	return pr
}

// GAWCC labels each node with the smallest node id in its weakly
// connected component (undirected flood in ascending sweep order).
func GAWCC(g *chickpeas.Snapshot) []uint32 {
	n := g.NodeCount()
	comp := make([]uint32, n)
	for i := range comp {
		comp[i] = math.MaxUint32
	}
	var stack []uint32
	for s := range n {
		if comp[s] != math.MaxUint32 {
			continue
		}
		comp[s] = s
		stack = append(stack[:0], s)
		for len(stack) > 0 {
			v := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			for u := range g.Neighbors(v, chickpeas.Both) {
				if comp[u] == math.MaxUint32 {
					comp[u] = s
					stack = append(stack, u)
				}
			}
		}
	}
	return comp
}

// GACDLPSeeded is synchronous label propagation from explicit initial
// labels (seed with original vertex ids so the smallest-label tie-break
// operates in vertex-id space, matching the references). Directed
// graphs tally incoming and outgoing separately, so a mutual rel counts
// twice.
func GACDLPSeeded(g *chickpeas.Snapshot, directed bool, iterations int, init []uint32) []uint32 {
	n := int(g.NodeCount())
	cur := slices.Clone(init)
	next := make([]uint32, n)
	for range iterations {
		parallel.For(n, func(lo, hi int) {
			// Per-chunk scratch (a few dozen chunks per pass); reused
			// across the chunk's nodes.
			var buf []uint32
			for v := lo; v < hi; v++ {
				buf = buf[:0]
				if directed {
					for u := range g.Neighbors(uint32(v), chickpeas.Outgoing) {
						buf = append(buf, cur[u])
					}
					for u := range g.Neighbors(uint32(v), chickpeas.Incoming) {
						buf = append(buf, cur[u])
					}
				} else {
					for u := range g.Neighbors(uint32(v), chickpeas.Both) {
						buf = append(buf, cur[u])
					}
				}
				slices.Sort(buf)
				best, bestCount := cur[v], 0
				for i := 0; i < len(buf); {
					lab := buf[i]
					j := i + 1
					for j < len(buf) && buf[j] == lab {
						j++
					}
					if j-i > bestCount {
						bestCount = j - i
						best = lab
					}
					i = j
				}
				next[v] = best
			}
		})
		cur, next = next, cur
	}
	return cur
}

// GALCC is the local clustering coefficient: rels among each node's
// undirected neighbour set over k*(k-1), forward rels counting.
func GALCC(g *chickpeas.Snapshot, directed bool) []float64 {
	n := int(g.NodeCount())
	out := gaFwd(directed)

	// Sorted forward-adjacency (CSR), built once; the triangle count
	// probes the smaller side of each intersection.
	off := make([]uint32, n+1)
	for v := range n {
		var d uint32
		for range g.Neighbors(uint32(v), out) {
			d++
		}
		off[v+1] = off[v] + d
	}
	adj := make([]uint32, off[n])
	for v := range n {
		s := off[v]
		p := s
		for w := range g.Neighbors(uint32(v), out) {
			adj[p] = w
			p++
		}
		slices.Sort(adj[s:p])
	}

	result := make([]float64, n)
	nWords := (n + 63) / 64
	parallel.For(n, func(lo, hi int) {
		// Per-chunk scratch: the N(v) membership bitset and neighbour
		// buffer, reused across the chunk's nodes.
		mark := make([]uint64, nWords)
		var nbrs []uint32
		for v := lo; v < hi; v++ {
			nbrs = nbrs[:0]
			for u := range g.Neighbors(uint32(v), chickpeas.Both) {
				marked := mark[u>>6]>>(u&63)&1 != 0
				if u != uint32(v) && !marked {
					mark[u>>6] |= 1 << (u & 63)
					nbrs = append(nbrs, u)
				}
			}
			k := len(nbrs)
			if k >= 2 {
				needSort := false
				for _, u := range nbrs {
					if int(off[u+1]-off[u]) > k {
						needSort = true
						break
					}
				}
				if needSort {
					slices.Sort(nbrs)
				}
				var rels uint64
				for _, u := range nbrs {
					uo := adj[off[u]:off[u+1]]
					if len(uo) <= k {
						for _, w := range uo {
							if w != u && mark[w>>6]>>(w&63)&1 != 0 {
								rels++
							}
						}
					} else {
						cursor := 0
						for _, w := range nbrs {
							if w == u {
								continue
							}
							found, pos := gaGallop(uo, cursor, w)
							cursor = pos
							if found {
								rels++
							}
						}
					}
				}
				result[v] = float64(rels) / (float64(k) * (float64(k) - 1.0))
			}
			for _, u := range nbrs {
				mark[u>>6] &^= 1 << (u & 63)
			}
		}
	})
	return result
}

// GASSSP is single-source shortest paths over forward rels (weight rel
// property, absent = 1.0); unreachable nodes get +Inf.
func GASSSP(g *chickpeas.Snapshot, source uint32, directed bool) []float64 {
	var wcol chickpeas.F64Col
	hasCol := false
	if c, ok := g.RelCol("weight"); ok {
		wcol = c.F64()
		hasCol = true
	}
	weight := func(_ chickpeas.NodeID, rel chickpeas.RelRef) float64 {
		if hasCol {
			if w, ok := wcol.Get(rel.Pos); ok {
				return w
			}
		}
		return 1.0
	}
	sp := g.Dijkstra(source, gaFwd(directed), chickpeas.MatchAll(), weight)
	n := g.NodeCount()
	out := make([]float64, n)
	for v := range n {
		if d, ok := sp.Distance(v); ok {
			out[v] = d
		} else {
			out[v] = math.Inf(1)
		}
	}
	return out
}
